async function loadAll(){const core=await Promise.all([api('/api/me'),api('/api/projects'),api('/api/styles'),api('/api/models'),api('/api/assets')]);[state.me,state.projects,state.styles,state.models,state.assets]=core;if(can('usage.view'))await loadUsage();if(can('users.manage'))state.users=await api('/api/users').catch(()=>[]);await loadSecrets();if(state.selected)await refreshSelected()}
async function loadUsage(){if(!can('usage.view'))return;state.usage=await api(`/api/usage?days=${state.usageDays}&user_id=${encodeURIComponent(state.usageUser)}`).catch(()=>state.usage||{})}
async function setUsageFilter(days,userId){if(days!=null)state.usageDays=Number(days);if(userId!=null)state.usageUser=userId;await loadUsage();render()}
function niceCeil(v){if(v<=0)return 1;const p=Math.pow(10,Math.floor(Math.log10(v)));const n=v/p;return (n<=1?1:n<=2?2:n<=5?5:10)*p}
function usageChart(){const d=state.usage.by_day||[];if(!d.length)return '<p class="muted-note">Немає запусків у вибраному періоді.</p>';const max=niceCeil(Math.max(...d.map(x=>x.cost)));const fmt=v=>'$'+(max<1?v.toFixed(2):max<10?v.toFixed(1):Math.round(v));const lines=[1,.75,.5,.25,0];return `<div class="uchart"><div class="uaxis">${lines.map(f=>`<small style="bottom:calc(${f*100}% - 6px)">${fmt(max*f)}</small>`).join('')}</div><div class="uplot"><div class="ubars-zone">${lines.map(f=>`<i class="ugrid ${f===0?'zero':''}" style="bottom:${f*100}%"></i>`).join('')}<div class="ubars">${d.map(x=>`<div class="ubar-wrap" title="${x.day}: ${money(x.cost)} · ${x.projects} проєкт(и)"><div class="ubar" style="height:${Math.max(2,x.cost/max*100)}%"></div></div>`).join('')}</div></div><div class="ulabels">${d.map(x=>`<small>${x.day.slice(x.day.length>7?5:2)}</small>`).join('')}</div></div></div>`}
function usageUserTable(){const list=state.usage.by_user||[];if(!list.length)return '';return `<section class="panel"><h2>По користувачах</h2><div class="table-wrap"><table><thead><tr><th>Користувач</th><th>Проєкти</th><th>Вартість</th><th>Токени (вх/вих)</th><th>Зображення</th><th>Схвалено</th></tr></thead><tbody>${list.map(u=>`<tr class="${state.usageUser===u.user_id?'urow-active':''}" onclick="setUsageFilter(null,state.usageUser==='${u.user_id}'?'':'${u.user_id}')"><td>${esc(u.name)}</td><td>${u.projects}</td><td>${money(u.cost)}</td><td>${u.input_tokens} / ${u.output_tokens}</td><td>${u.images}</td><td>${u.approved}</td></tr>`).join('')}</tbody></table></div><p class="muted-note">Клік по рядку фільтрує картки та графік за цим користувачем; повторний клік знімає фільтр.</p></section>`}
async function refreshSelected(){const [p,e]=await Promise.all([api(`/api/projects/${state.selected.id}`),api(`/api/projects/${state.selected.id}/events`)]);state.selected=p;state.events=e;selectArtifact(state.artifact?.id,false)}
let live,liveSig='',liveFails=0;
function liveSignature(){return JSON.stringify({page:state.page,tab:state.tab,projects:state.projects.map(x=>[x.id,x.status,x.stage,x.progress,x.estimated_cost,x.name,x.sku,x.product_category]),sel:state.selected?[state.selected.id,state.selected.status,state.selected.stage,state.selected.progress,state.selected.estimated_cost,(state.selected.artifacts||[]).length,(state.selected.critics||[]).length,state.events[0]?.id]:null,assets:state.page==='media'?state.assets.length:0})}
function startLive(){clearInterval(live);liveSig=liveSignature();live=setInterval(async()=>{if(!state.token)return;try{state.projects=await api('/api/projects');if(state.selected)await refreshSelected();else if(state.page==='media')state.assets=await api('/api/assets');liveFails=0;setOffline(false);const sig=liveSignature();if(sig===liveSig)return;const active=document.activeElement;const userIsInteracting=document.querySelector('dialog[open]')||active?.matches('input,textarea,select,iframe')||(state.selected&&['preview','html'].includes(state.tab));if(userIsInteracting)return;liveSig=sig;const y=scrollY;render();scrollTo(0,y)}catch{liveFails++;if(liveFails>=2)setOffline(true)}},2500)}
