function loginView(){root.innerHTML=`<div class="auth"><canvas class="pixel-bg"></canvas><img class="auth-logo" src="${LOGO}" alt="ARTLINE"><form onsubmit="login(event)"><h1>Вхід до робочого простору</h1><p>Генерація та керування rich-контентом.</p><label>Email<input name="email" type="email" required></label><label>Пароль<input name="password" type="password" required></label><button class="btn primary">Увійти</button>${state.authMethods?.github?`<div class="auth-or">або</div><button type="button" class="btn secondary" onclick="location.href='/api/auth/github'">Увійти через GitHub</button>`:''}</form></div>`;startPixelField(document.querySelector('.auth .pixel-bg'))}
// Access is driven by effective permissions (role defaults + per-user overrides),
// resolved by the API and returned in state.me.permissions. The UI mirrors them.
const can=p=>(state.me?.permissions||[]).includes(p);
const allowedPages=()=>['projects',...(can('style.manage')?['styles']:[]),...(can('media.view')?['media']:[]),...(can('usage.view')?['usage']:[]),...(can('users.manage')?['users']:[]),...(can('settings.view')?['settings']:[])];
function allowedTabs(){const t=['overview','preview'];if(can('project.edit_html'))t.push('html');if(can('media.view'))t.push('assets');if(can('review.request_changes')||can('review.approve'))t.push('review');t.push('activity');return t}
function shell(content){const pages=allowedPages(),nav=[['projects','Проєкти'],['styles','Стилі'],['media','Медіа'],['usage','Використання'],['users','Користувачі'],['settings','Налаштування']].filter(x=>pages.includes(x[0]));root.innerHTML=`<div class="shell"><aside><div class="brand-lockup"><img src="${LOGO}" alt="ARTLINE"><small>Rich Studio</small></div><nav>${nav.map(([k,v])=>`<button class="${state.page===k?'active':''}" onclick="go('${k}')">${v}</button>`).join('')}</nav><div class="userbox"><b>${esc(state.me?.name||state.me?.email)}</b><small>${ROLE_LABEL[state.me?.role]||esc(state.me?.role)}</small><button onclick="logout()">Вийти</button></div></aside><main><div class="appbar"><span>Платформа AI rich-контенту</span><span class="api-state">${state.models.source==='openai+configuration'?'Моделі OpenAI синхронізовано':'Моделі з конфігурації'}</span></div><div class="container">${content}</div></main></div>`}
function go(page){state.page=page;state.selected=null;state.styleEdit=null;if(page==='settings')loadSystem().then(render);if(page==='usage')loadUsage().then(render);render()}
const projectCategories=()=>[...new Set(state.projects.map(x=>(x.product_category||'').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'uk'));
function filtered(){let rows=[...state.projects],q=state.search.toLowerCase().trim();if(q)rows=rows.filter(x=>(x.name+' '+x.source_url+' '+x.text_model+' '+(x.sku||'')+' '+(x.product_category||'')).toLowerCase().includes(q));if(state.status!=='all')rows=rows.filter(x=>x.status===state.status);if(state.category!=='all')rows=rows.filter(x=>state.category==='none'?!(x.product_category||'').trim():(x.product_category||'').trim()===state.category);const split=state.sort.lastIndexOf('_'),key=state.sort.slice(0,split),dir=state.sort.slice(split+1);rows.sort((a,b)=>{let av,bv;if(key==='name'){av=(a.name||'').toLowerCase();bv=(b.name||'').toLowerCase()}else if(key==='category'){av=(a.product_category||'￿').toLowerCase();bv=(b.product_category||'￿').toLowerCase();const c=av.localeCompare(bv,'uk');return c*(dir==='asc'?1:-1)||(a.name||'').localeCompare(b.name||'','uk')}else if(key==='cost'){av=a.estimated_cost||0;bv=b.estimated_cost||0}else if(key==='duration'){av=a.duration_seconds||0;bv=b.duration_seconds||0}else{av=new Date(a[key]||0).getTime();bv=new Date(b[key]||0).getTime()}return (av>bv?1:av<bv?-1:0)*(dir==='asc'?1:-1)});return rows}
function badge(s){return `<span class="badge ${s}">${STATUS[s]||s}</span>`}
// Progress with motion. render() rebuilds the DOM, so a bare CSS transition has
// nothing to animate - the bar is born at its final width. We remember the last
// shown value per project, render at the OLD width and let animateProgressBars()
// move it to the new one on the next frame, so the browser tweens for real.
const PROGRESS_MEMO={};
function progress(p,active=false,id=''){const pct=Math.max(0,Math.min(100,Number(p)||0));const prev=(id&&id in PROGRESS_MEMO)?PROGRESS_MEMO[id]:pct;const dot=active&&pct>0&&pct<100?`<b class="phead" style="left:${prev}%" data-left="${pct}"></b>`:'';return `<div class="progress ${active?'run':''}"><i style="width:${prev}%" data-w="${pct}" data-pid="${esc(id)}"></i>${dot}</div>`}
function animateProgressBars(){requestAnimationFrame(()=>{document.querySelectorAll('.progress i[data-w]').forEach(el=>{el.style.width=el.dataset.w+'%';if(el.dataset.pid)PROGRESS_MEMO[el.dataset.pid]=Number(el.dataset.w)});document.querySelectorAll('.progress .phead[data-left]').forEach(el=>{el.style.left=el.dataset.left+'%'});const mk=Object.keys(PROGRESS_MEMO);for(let i=0;i<mk.length-100;i++)delete PROGRESS_MEMO[mk[i]]})}
function setProjectView(view){state.projectView=view;localStorage.setItem('projectView',view);render()}
function primeEstimate(){const f=document.querySelector('#newProject form');if(f)updateEstimate(f)}
function projectsPage(){const rows=filtered(),cats=projectCategories(),sortOptions=[['finished_at_desc','Нещодавно завершені'],['created_at_desc','Спочатку нові'],['created_at_asc','Спочатку старі'],['name_asc','За назвою'],['category_asc','За категорією'],['cost_desc','За вартістю'],['duration_desc','За часом']];shell(`<header class="pagehead"><div><small class="eyebrow">КЕРУВАННЯ КОНТЕНТОМ ARTLINE</small><h1>Проєкти</h1><p>Вставте посилання на товар — назва визначиться автоматично.</p></div>${can('project.create')?`<button class="btn primary" onclick="state.uploads=[];state.uploads360=false;newProject.showModal();primeEstimate()">+ Новий проєкт</button>`:''}</header><section class="toolbar project-toolbar"><input placeholder="Пошук за назвою, артикулом, URL або моделлю" value="${esc(state.search)}" oninput="state.search=this.value;render()"><select onchange="state.status=this.value;render()"><option value="all">Усі статуси</option>${Object.entries(STATUS).map(([k,v])=>`<option value="${k}" ${state.status===k?'selected':''}>${v}</option>`).join('')}</select><select onchange="state.category=this.value;render()"><option value="all">Усі категорії</option>${cats.map(c=>`<option value="${esc(c)}" ${state.category===c?'selected':''}>${esc(c)}</option>`).join('')}<option value="none" ${state.category==='none'?'selected':''}>Без категорії</option></select><select onchange="state.sort=this.value;render()">${sortOptions.map(([value,label])=>`<option value="${value}" ${state.sort===value?'selected':''}>${label}</option>`).join('')}</select><div class="view-switch" aria-label="Вигляд проєктів"><button class="${state.projectView==='cards'?'active':''}" onclick="setProjectView('cards')">Картки</button><button class="${state.projectView==='list'?'active':''}" onclick="setProjectView('list')">Список</button></div></section><section class="project-grid ${state.projectView==='list'?'list-view':''}">${rows.map(p=>`<article class="project" role="button" tabindex="0" onclick="openProject('${p.id}')" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();openProject('${p.id}')}" ><div class="project-top">${badge(p.status)}<small title="${dt(p.created_at)}">${rel(p.created_at)}</small></div><h3 title="${esc(p.name)}">${esc(p.name)}</h3><p>${esc(p.source_url)}</p><p class="project-sku">Артикул: <b>${p.sku?esc(p.sku):'—'}</b></p><div class="stage-row"><span>${STAGE[p.stage]||'Опрацювання'}</span><b>${p.progress||0}%</b></div>${progress(p.progress,['processing','queued'].includes(p.status),p.id)}<div class="project-style">${p.product_category?`<span class="cat-chip">${esc(p.product_category)}</span>`:''}Стиль: <b>${esc(p.style_name||'Не визначено')}</b></div><div class="project-meta"><span title="Текстова модель">${esc(p.text_model)}</span><span title="Вартість запуску">${money(p.estimated_cost)}</span><span title="Час виконання">${dur(p.duration_seconds)}</span></div></article>`).join('')||emptyProjects()}</section>${projectDialog()}`)}
function emptyProjects(){const hasFilters=state.search||state.status!=='all'||state.category!=='all';if(hasFilters&&state.projects.length)return `<div class="empty"><b>Нічого не знайдено</b><p>Змініть пошук або фільтри — проєкти є, але вони приховані поточними умовами.</p><button class="btn secondary" onclick="state.search='';state.status='all';state.category='all';render()">Скинути фільтри</button></div>`;return `<div class="empty"><b>Проєктів поки немає</b><p>Вставте посилання на сторінку товару — система збере факти й характеристики, підготує зображення та згенерує rich-контент кількома мовами.</p>${['admin','editor'].includes(state.me?.role)?`<button class="btn primary" onclick="newProject.showModal()">+ Створити перший проєкт</button>`:''}</div>`}
function options(items,selected){return items.map(x=>`<option value="${esc(x)}" ${x===selected?'selected':''}>${esc(x)}</option>`).join('')}
function dataList(id,items){return `<datalist id="${id}">${items.map(x=>`<option value="${esc(x)}"></option>`).join('')}</datalist>`}
const QUICK_LANGS=['ua','ru','pl'];
function languagePicker(selected=['ua','ru']){const chosen=new Set(selected||[]),custom=[...chosen].filter(x=>!QUICK_LANGS.includes(x)),extra=[...LANGUAGE_OPTIONS.filter(x=>!QUICK_LANGS.includes(x)),'bg','lt','lv','et','uk'];return `<fieldset class="language-fieldset"><legend>Мови результату</legend><div class="language-grid">${QUICK_LANGS.map(code=>`<label class="check"><input type="checkbox" name="language" value="${code}" ${chosen.has(code)?'checked':''}> ${LANG[code]}</label>`).join('')}</div><label class="custom-language">Додати інші мови <em>почніть вводити код: en, de, fr, es, bg, en-GB…</em><input name="custom_languages" value="${esc(custom.join(', '))}" placeholder="en, de, fr, es, it, cs…" list="extraLangs"></label>${dataList('extraLangs',extra)}</fieldset>`}
function collectLanguages(form){const values=[...form.querySelectorAll('[name=language]:checked')].map(x=>x.value),custom=String(new FormData(form).get('custom_languages')||'').split(/[\s,;]+/).map(x=>x.trim()).filter(Boolean);return [...new Set([...values,...custom])]}
// Cost presets. The dialog had six knobs, of which four only moved the price.
// Simple mode folds those four into one choice; content decisions (URL, languages)
// stay visible in both modes because they are not a cost trade-off.
const PRESETS={
  eco:{name:'Економний',note:'Чернетка: подивитись на структуру й текст, не платячи за картинки',text:['gpt-5-mini','gpt-4.1-mini'],image:['gpt-image-1-mini','gemini-2.5-flash-image','gpt-image-1'],quality:'low'},
  std:{name:'Стандарт',note:'Робочий режим для більшості карток',text:['gpt-5-mini','gpt-4.1-mini'],image:['gemini-2.5-flash-image','gpt-image-1'],quality:'medium'},
  max:{name:'Максимум',note:'Флагманські товари, максимальна деталізація',text:['gpt-5','gpt-5-mini'],image:['gpt-image-2','gpt-image-1','gemini-3-pro-image-preview'],quality:'high'},
};
// A run bills roughly this many tokens; used only to price the dialog, never to charge.
const EST_TOKENS={input:30000,output:14000};
const firstAvailable=(wanted,have,fallback)=>wanted.find(x=>(have||[]).includes(x))||fallback||(have||[])[0]||'';
function resolvePreset(key){const p=PRESETS[key]||PRESETS.std;return {key,...p,text_model:firstAvailable(p.text,state.models.text_models,state.models.default_text_model),image_model:firstAvailable(p.image,state.models.image_models,state.models.default_image_model)}}
function imageRate(model,quality){const row=(state.models.image_pricing||{})[model];if(!row)return 0.07;const v=row[quality];return Number(v!=null?v:(row.medium!=null?row.medium:0.07))}
function textRate(model){const row=(state.models.text_pricing||{})[model];if(!row)return 0.04;return (EST_TOKENS.input*Number(row.input||0)+EST_TOKENS.output*Number(row.output||0))/1e6}
// Hero desktop + Hero mobile + Feature when both formats are on; two otherwise.
function estimateCost(textModel,imageModel,quality,variants){return imageRate(imageModel,quality)*(variants>1?3:2)+textRate(textModel)}
const estLabel=n=>`≈ $${n.toFixed(2)}`;
// render() rebuilds the whole document, so whatever the user typed into the dialog
// lives only in the DOM and dies with it. Carry their own input across the re-render.
// Model/quality/style are deliberately NOT carried: the preset owns those, and
// restoring them would undo the very click that triggered the re-render.
const KEEP_FIELDS=['source_url','style_id','custom_languages','custom_hero_url','custom_feature_url'];
const KEEP_CHECKS=['language','variant'];
function formSnapshot(form){if(!form)return null;const d={v:{},c:{}};for(const el of form.elements){if(!el.name)continue;if(KEEP_FIELDS.includes(el.name))d.v[el.name]=el.value;else if(KEEP_CHECKS.includes(el.name))d.c[el.name+'='+el.value]=el.checked}return d}
function formRestore(form,d){if(!form||!d)return;for(const el of form.elements){if(!el.name)continue;if(el.name in d.v){el.value=d.v[el.name];continue}const k=el.name+'='+el.value;if(k in d.c)el.checked=d.c[k]}}
function rerenderProjectDialog(){const dlg=document.getElementById('newProject'),open=dlg&&dlg.open,snap=formSnapshot(dlg&&dlg.querySelector('form'));render();const next=document.getElementById('newProject');if(open&&next){next.showModal();formRestore(next.querySelector('form'),snap);primeEstimate()}}
function setProjectMode(m){state.projectMode=m;localStorage.setItem('projectMode',m);rerenderProjectDialog()}


function updateEstimate(form){const out=document.getElementById('advEstimate');if(!out||!form)return;const f=new FormData(form),variants=form.querySelectorAll('[name=variant]:checked').length;out.textContent=variants?estLabel(estimateCost(f.get('text_model'),pickedImageModel(f),f.get('image_quality'),variants)):'—'}
function advancedFields(){return `<div class="form-grid"><label>Стиль<select name="style_id" onchange="renderProbe()">${state.styles.map(s=>`<option value="${s.id}" ${s.is_default?'selected':''}>${esc(s.name)}</option>`).join('')}</select></label><label><span class="lbl">Текстова модель ${hint('Модель для аналізу товару, генерації та перекладу тексту. Впливає на якість тексту й вартість токенів.')}</span><select name="text_model">${options([...new Set([state.models.default_text_model,...(state.models.text_models||[])].filter(Boolean))],state.models.default_text_model)}</select></label><label><span class="lbl">Модель зображень ${hint('Модель для генерації Hero/Feature зображень із реального фото товару. Разом із «Якість» визначає вартість зображень.')}</span>${imageModelField()}</label><label><span class="lbl">Якість ${hint('Деталізація й роздільність AI-зображень Hero та Feature і їх вартість. gpt-image-1: low ≈ $0.02, medium ≈ $0.07, high ≈ $0.19 за зображення. Діє лише коли стиль генерує зображення (є Hero/Feature промпти й знайдено фото товару).')}</span><select name="image_quality"><option>low</option><option selected>medium</option><option>high</option></select></label></div><div class="form-grid"><label>Власне Hero URL <em>необов’язково</em><input name="custom_hero_url" type="url" placeholder="https://..."></label><label>Власне Feature URL <em>необов’язково</em><input name="custom_feature_url" type="url" placeholder="https://..."></label></div><p class="est-line">Орієнтовна вартість запуску: <b id="advEstimate">—</b>${hint('Оцінка до старту: три зображення за обраною моделлю та якістю плюс типовий обсяг тексту. Фактична вартість рахується після завершення за реальними токенами.')}</p>`}
function presetCard(k){const p=resolvePreset(k),cost=estimateCost(p.text_model,p.image_model,p.quality,2);const photo=IMAGE_MODEL_NOTES[p.image_model]||p.image_model;return `<button type="button" class="preset ${state.preset===k?'active':''}" data-k="${k}" onclick="pickPresetCard('${k}')"><span class="preset-top"><b>${esc(PRESETS[k].name)}</b><span class="preset-cost">${estLabel(cost)}</span></span><small>${esc(PRESETS[k].note)}</small><span class="preset-facts"><span><i>Фото</i>${esc(photo)}</span><span><i>Якість</i>${esc(p.quality)} · ${esc(p.image_model)}</span><span><i>Текст</i>${esc(p.text_model)}</span></span></button>`}
function simpleFields(){const p=resolvePreset(state.preset),def=(state.styles.find(x=>x.is_default)||state.styles[0]||{}).id||'';return `<label>Стиль<select name="style_id" onchange="renderProbe()">${state.styles.map(x=>`<option value="${x.id}" ${x.id===def?'selected':''}>${esc(x.name)}${x.is_default?' · базовий':''}</option>`).join('')}</select></label><fieldset><legend>Режим генерації</legend><div class="preset-grid">${['eco','std','max'].map(presetCard).join('')}</div><p class="est-line muted-note">Моделі та якість обирає пресет. Потрібен інший набір — перемкніть на «Розширений».</p></fieldset><input type="hidden" name="text_model" value="${esc(p.text_model)}"><input type="hidden" name="image_model" value="${esc(p.image_model)}"><input type="hidden" name="image_quality" value="${esc(p.quality)}">`}
// Card click updates in place: a full render() would rebuild the dialog and eat
// whatever the operator already typed into it.
function pickPresetCard(k){state.preset=k;localStorage.setItem('projectPreset',k);const f=document.querySelector('#newProject form');if(!f)return;const p=resolvePreset(k);for(const [name,val] of [['text_model',p.text_model],['image_model',p.image_model],['image_quality',p.quality]]){const el=f.querySelector(`input[type=hidden][name=${name}]`);if(el)el.value=val}f.querySelectorAll('.preset-grid .preset').forEach(b=>b.classList.toggle('active',b.dataset.k===k))}
// Page probe: a free scrape that shows what the run will be built from before it
// starts. Vital for Showcase, whose layout is fuelled by real gallery frames.
function isShowcaseSelected(){const f=document.querySelector('#newProject form');const id=f?new FormData(f).get('style_id'):null;const st=state.styles.find(x=>x.id===id)||state.styles.find(x=>x.is_default)||state.styles[0];return /showcase/i.test(st?.name||'')}
async function probePage(){const f=document.querySelector('#newProject form');const url=(f&&new FormData(f).get('source_url')||'').trim();if(!url||!/^https?:\/\//.test(url))return;if(state.probe?.url===url||state.probeBusy)return;state.probeBusy=true;renderProbe();try{const r=await api('/api/projects/probe',{method:'POST',body:JSON.stringify({source_url:url})});state.probe={url,name:r.name,frames:(r.gallery||[]).map(u=>({url:u,on:true})),prior:r.prior?{...r.prior,images:r.prior.images.map(x=>({...x,on:true}))}:null,usePrior:!!r.prior}}catch(x){state.probe={url,error:x.message,frames:[]}}state.probeBusy=false;renderProbe()}
function frameError(i){const f=state.probe?.frames?.[i];if(!f||f.dead)return;f.dead=true;f.on=false;renderProbe()}
function togglePrior(i){const x=state.probe?.prior?.images?.[i];if(!x)return;x.on=!x.on;renderProbe()}
function clearRoleEverywhere(role){(state.uploads||[]).forEach(x=>{if(x.role===role)x.role=''});(state.probe?.frames||[]).forEach(x=>{if(x.role===role)x.role=''})}
function toggleFrame(i){const x=state.probe?.frames?.[i];if(!x)return;x.on=!x.on;if(!x.on)x.role='';renderProbe()}
function setFrameRole(i,role){const x=state.probe?.frames?.[i];if(!x||x.dead)return;if(x.role===role){x.role=''}else{clearRoleEverywhere(role);x.role=role;x.on=true}renderProbe();renderUploadGrid()}
function selectedFrames(){return (state.probe?.frames||[]).filter(x=>x.on&&!x.dead).map(x=>x.url)}
function probeBoxTpl(){if(state.probeBusy)return '<div class="probe-note">Читаємо сторінку…</div>';const pr=state.probe;if(!pr)return '<div class="probe-note muted-note">Вставте посилання — студія покаже назву товару і кадри галереї ще до запуску.</div>';if(pr.error)return `<div class="probe-note quality-bad">Не вдалося прочитати сторінку: ${esc(pr.error)}</div>`;const n=selectedFrames().length;const showcase=isShowcaseSelected();const verdict=showcase?(n>=4?`<span class="verdict ok">${n} кадрів — достатньо для Showcase</span>`:`<span class="verdict bad">${n} кадр(и) — для Showcase замало, макет виродиться. Краще ARTLINE Engineering</span>`):`<span class="verdict">${n} кадрів галереї</span>`;const PRIOR_LABEL={'hero-desktop-generated':'Hero Desktop','hero-mobile-generated':'Hero Mobile','feature-generated':'Feature','hero-custom':'Hero (власне)','feature-custom':'Feature (власне)'};const prior=pr.prior?`<div class="prior-strip"><label class="check"><input type="checkbox" ${pr.usePrior?'checked':''} onchange="state.probe.usePrior=this.checked;renderProbe()"> Використати готові AI-зображення з попередньої генерації <b>без витрат</b></label>${pr.usePrior?`<div class="prior-thumbs">${pr.prior.images.map((x,i)=>`<button type="button" class="prior-thumb ${x.on?'':'off'}" onclick="togglePrior(${i})" title="${x.on?'Клік — перегенерувати це зображення заново':'Клік — використати готове'}"><img src="${esc(x.url)}" alt="${esc(PRIOR_LABEL[x.label]||x.label)}" loading="lazy"><i>${esc(PRIOR_LABEL[x.label]||x.label)}</i></button>`).join('')}</div><p class="muted-note probe-note">Зібрано з усіх попередніх генерацій цього товару. Вимкнене зображення буде згенеровано заново (платно), решта копіюються без витрат.</p>`:''}</div>`:'';return `<div class="probe-head"><b>${esc(pr.name||'Без назви')}</b>${verdict}</div>${prior}<div class="probe-grid">${pr.frames.map((x,i)=>`<div class="uwrap"><button type="button" class="frame ${x.dead?'dead':''} ${x.on?'':'off'}" onclick="toggleFrame(${i})" title="${x.on?'Клік — виключити кадр':'Клік — повернути кадр'}"><img src="${esc(x.url)}" alt="Кадр ${i+1}" loading="lazy" onerror="frameError(${i})"></button>${x.dead?``:`<div class="role-row"><button type="button" class="role-chip ${x.role==='hero'?'active':''}" title="Цей кадр стане головним Hero без AI-генерації" onclick="setFrameRole(${i},'hero')">Hero</button><button type="button" class="role-chip ${x.role==='feature'?'active':''}" title="Цей кадр стане Feature-блоком без AI-генерації" onclick="setFrameRole(${i},'feature')">Фіча</button></div>`}</div>`).join('')}</div><p class="muted-note probe-note">Клік по кадру виключає його з генерації. Вимкнені кадри не потраплять у Showcase.</p>`}
function renderProbe(){const box=document.getElementById('probeBox');if(box)box.innerHTML=probeBoxTpl()}
function uploadGridTpl(){const list=state.uploads||[];if(!list.length)return '<p class="muted-note">Ще нічого не завантажено — це необов\'язковий крок.</p>';return list.map((u,i)=>`<div class="uwrap"><div class="frame ${u.on?'':'off'}" title="${esc(u.name||'')}" onclick="toggleUpload(${i})">${u.busy?'<span class="upload-busy">…</span>':`<img src="${u.url}" loading="lazy" alt="">`}${state.uploads360?`<b class="frame-num">${i+1}</b>`:``}<button type="button" class="frame-x" aria-label="Прибрати" onclick="event.stopPropagation();removeUpload(${i})">×</button></div>${state.uploads360?``:`<div class="role-row"><button type="button" class="role-chip ${u.role==='hero'?'active':''}" title="Це фото стане головним Hero без AI-генерації" onclick="setUploadRole(${i},'hero')">Hero</button><button type="button" class="role-chip ${u.role==='feature'?'active':''}" title="Це фото стане Feature-блоком без AI-генерації" onclick="setUploadRole(${i},'feature')">Фіча</button></div>`}</div>`).join('')}
function renderUploadGrid(){const g=document.getElementById('uploadGrid');if(g)g.innerHTML=uploadGridTpl();const h=document.getElementById('upload360Hint');if(h)h.innerHTML=upload360HintTpl()}
function upload360HintTpl(){if(!state.uploads360)return '';const n=(state.uploads||[]).filter(u=>u.on&&u.url).length;if(n<2)return `<p class="critic-note">Для обертання потрібно щонайменше 2 кадри (зараз ${n}). Комфортний мінімум — 12.</p>`;if(n<12)return `<p class="muted-note">${n} кадр(ів): обертання буде помітно «стрибати». Рекомендовано 12–24 кадри по колу.</p>`;return `<p class="muted-note">${n} кадр(ів) — цього вистачає для плавного обертання. Перевірте порядок за номерами на мініатюрах.</p>`}
function toggleUploads360(on){state.uploads360=on;if(on){const s360=(state.styles||[]).find(x=>x.name==='ARTLINE Podium 3D 360');const sel=document.querySelector('#newProject select[name=style_id]');if(s360&&sel&&sel.value!==s360.id){sel.value=s360.id;if(typeof renderProbe==='function')renderProbe();toast('Стиль переключено на ARTLINE Podium 3D 360')}}renderUploadGrid()}
function toggleUpload(i){const u=(state.uploads||[])[i];if(!u||u.busy)return;u.on=!u.on;if(!u.on)u.role='';renderUploadGrid()}
function setUploadRole(i,role){const list=state.uploads||[],u=list[i];if(!u||u.busy)return;if(u.role===role){u.role=''}else{clearRoleEverywhere(role);u.role=role;u.on=true}renderUploadGrid();renderProbe()}
function removeUpload(i){(state.uploads||[]).splice(i,1);renderUploadGrid()}
async function uploadRefs(input){const files=[...(input.files||[])];input.value='';for(const file of files){if((state.uploads||[]).length>=36){toast('Максимум 36 фото (вистачає на повне коло 360)',true);break}
const slot={url:'',name:file.name,on:true,busy:true};state.uploads.push(slot);renderUploadGrid();
try{const r=await fetch('/api/uploads/image',{method:'POST',headers:{Authorization:`Bearer ${state.token}`,'Content-Type':'application/octet-stream'},body:file});const d=await r.json().catch(()=>null);if(!r.ok)throw Error(d?.detail||`HTTP ${r.status}`);slot.url=d.url;slot.busy=false}
catch(x){state.uploads=state.uploads.filter(s=>s!==slot);toast(`${file.name}: ${x.message}`,true)}
renderUploadGrid()}}
function projectDialog(){return `<dialog id="newProject"><form onsubmit="createProject(event)" oninput="updateEstimate(this.form||this)" onchange="updateEstimate(this.form||this)"><div class="dialog-head"><div><small class="eyebrow">НОВИЙ ПРОЄКТ</small><h2>Створити rich-контент</h2></div><button type="button" aria-label="Закрити" onclick="newProject.close()">×</button></div><div class="view-switch mode-switch" aria-label="Режим створення"><button type="button" class="${state.projectMode==='simple'?'active':''}" onclick="setProjectMode('simple')">Простий</button><button type="button" class="${state.projectMode==='advanced'?'active':''}" onclick="setProjectMode('advanced')">Розширений</button></div><label>Посилання на товар<input name="source_url" type="url" placeholder="https://artline.ua/..." required onblur="probePage()" onchange="probePage()"></label><div id="probeBox" class="probe-box">${probeBoxTpl()}</div><fieldset><legend>Додаткові фото (опційно)</legend><div class="upload-grid" id="uploadGrid">${uploadGridTpl()}</div><div class="row"><label class="btn secondary">Завантажити фото<input type="file" accept="image/*" multiple hidden onchange="uploadRefs(this)"></label><em class="muted-note">Клік по фото вмикає/вимикає його; кнопки Hero/Фіча призначають фото головним у відповідний блок — тоді AI його не генерує.</em></div><label class="check upload-360"><input type="checkbox" ${state.uploads360?'checked':''} onchange="toggleUploads360(this.checked)"> Це 360-серія: кадри зняті по колу (за порядком файлів) — стиль «ARTLINE Podium 3D 360» збере з них справжнє обертання</label><div id="upload360Hint">${upload360HintTpl()}</div><div style="display:none"</div></fieldset>${state.projectMode==='simple'?simpleFields():advancedFields()}${languagePicker(['ua','ru'])}<fieldset><legend>Формати</legend><div class="language-grid"><label class="check"><input type="checkbox" name="variant" value="desktop" checked> Десктоп</label><label class="check"><input type="checkbox" name="variant" value="mobile" checked> Мобільна</label></div></fieldset><button class="btn primary">Створити й запустити</button></form></dialog>`}
// Native <datalist> popups are drawn by the browser and cannot be styled or grouped.
// A <select> with <optgroup> separates the providers and renders as a normal control;
// the "Інша модель" option keeps the old freedom to type a model ID that is not listed yet.
