const IMAGE_MODEL_NOTES={
 'gpt-image-1':'еталон деталей і логотипів',
 'gpt-image-1-mini':'чернетки, найдешевша',
 'gpt-image-2':'нове покоління OpenAI',
 'gemini-2.5-flash-image':'найкраще тримає вигляд товару, дешева',
 'gemini-3.1-flash-image-preview':'новіша Nano Banana, баланс якість/ціна',
 'gemini-3-pro-image-preview':'максимальна якість Gemini',
};
const RECOMMENDED_IMAGE_MODELS=['gemini-2.5-flash-image','gpt-image-1'];
const imageModelLabel=x=>`${RECOMMENDED_IMAGE_MODELS.includes(x)?'★ ':''}${x}${IMAGE_MODEL_NOTES[x]?` — ${IMAGE_MODEL_NOTES[x]}`:''}`;
function imageModelField(){const all=state.models.image_models||[],cur=state.models.default_image_model||'';const gem=all.filter(x=>x.startsWith('gemini-')),oai=all.filter(x=>!x.startsWith('gemini-'));const known=all.includes(cur),group=(label,items,disabled)=>items.length?`<optgroup label="${esc(label)}" ${disabled?'disabled':''}>${items.map(x=>`<option value="${esc(x)}" ${!disabled&&cur===x?'selected':''} ${disabled?'disabled':''}>${esc(imageModelLabel(x))}</option>`).join('')}</optgroup>`:'';const gemGroup=gem.length?group('Gemini · Nano Banana',gem):group('Gemini · Nano Banana — потрібен ключ (Налаштування)',state.models.gemini_models||[],true);return `<select name="image_model" onchange="toggleCustomModel(this)">${group('OpenAI',oai)}${gemGroup}<option value="__custom__" ${cur&&!known?'selected':''}>Інша модель…</option></select><input name="image_model_custom" class="custom-model" placeholder="напр. gemini-3-pro-image-preview" spellcheck="false" value="${cur&&!known?esc(cur):''}" ${cur&&!known?'':'hidden'}>`}
function toggleCustomModel(sel){const box=sel.parentElement.querySelector('.custom-model');if(!box)return;const on=sel.value==='__custom__';box.hidden=!on;if(on)box.focus()}
function pickedImageModel(f){const v=f.get('image_model');return v==='__custom__'?(f.get('image_model_custom')||'').trim():v}
async function createProject(e){e.preventDefault();const form=e.currentTarget,f=new FormData(form),payload={source_url:f.get('source_url'),style_id:f.get('style_id')||null,text_model:f.get('text_model'),image_model:pickedImageModel(f),image_quality:f.get('image_quality'),custom_hero_url:(state.probe?.frames||[]).find(x=>x.role==='hero'&&x.on&&!x.dead)?.url||f.get('custom_hero_url')||'',custom_feature_url:(state.probe?.frames||[]).find(x=>x.role==='feature'&&x.on&&!x.dead)?.url||f.get('custom_feature_url')||'',languages:collectLanguages(form),variants:[...form.querySelectorAll('[name=variant]:checked')].map(x=>x.value),uploads:(state.uploads||[]).filter(u=>u.on&&u.url).map(u=>u.url),uploads_360:!!state.uploads360,upload_hero:(state.uploads||[]).find(u=>u.role==='hero'&&u.url)?.url||'',upload_feature:(state.uploads||[]).find(u=>u.role==='feature'&&u.url)?.url||''};try{if(state.probe&&!state.probe.error&&state.probe.url===payload.source_url){payload.gallery=selectedFrames();if(state.probe.prior&&state.probe.usePrior){const picked=state.probe.prior.images.filter(x=>x.on).map(x=>({project_id:x.project_id,label:x.label}));if(picked.length)payload.adopt_images=picked}}const p=await api('/api/projects',{method:'POST',body:JSON.stringify(payload)});newProject.close();toast('Проєкт додано до черги');await loadAll();await openProject(p.id)}catch(x){toast(x.message,true)}}
async function openProject(id){state.artifact=null;state.selected=await api(`/api/projects/${id}`);state.events=await api(`/api/projects/${id}/events`);state.tab='overview';selectArtifact(null,false);render()}
function selectArtifact(id,rerender=true){const list=state.selected?.artifacts||[],latest=[...list].sort((a,b)=>(b.version-a.version)||(new Date(b.created_at)-new Date(a.created_at)))[0]||null;state.artifact=(id&&list.find(x=>x.id===id))||state.artifact&&list.find(x=>x.id===state.artifact.id)||latest;if(rerender)render()}
function workspace(){const p=state.selected,limit=allowedTabs(),tabs=[['overview','Огляд'],['preview','Перегляд'],['html','HTML'],['assets','Медіа'],['review','Перевірка'],['activity','Історія']].filter(t=>!limit||limit.includes(t[0]));if(limit&&!limit.includes(state.tab))state.tab=limit[0];const liveState=['processing','queued'].includes(p.status)?'run':p.status==='error'?'bad':['paused','cancelled','changes_requested'].includes(p.status)?'warn':'ok';shell(`<header class="project-head"><div><button class="link" onclick="state.selected=null;render()">← Усі проєкти</button><h1>${esc(p.name)}</h1><a class="source-link" href="${esc(p.source_url)}" target="_blank" rel="noopener noreferrer" title="Відкрити сторінку товару">${esc(p.source_url)} ↗</a></div><div>${projectActions(p)}</div></header><section class="live-card ${liveState}"><div class="live-title"><div><span class="pulse"></span><b>${STAGE[p.stage]||'Опрацювання проєкту'}</b></div><strong>${p.progress||0}%</strong></div>${progress(p.progress,['processing','queued'].includes(p.status),p.id)}<small>${STATUS[p.status]||p.status}</small></section>${p.status==='error'&&p.error?`<section class="error-island"><b>Помилка генерації</b><p>${esc(p.error)}</p>${['admin','editor'].includes(state.me?.role)?`<button class="btn secondary" onclick="queueAction('resume',this)">Спробувати ще раз</button>`:''}</section>`:''}<section class="metrics project-metrics"><div><small>Стиль</small><b>${esc(p.style_name||'Не визначено')}</b></div><div><small>Текстова модель</small><b>${esc(p.text_model)}</b></div><div><small>Зображення</small><b>${esc(p.image_model)}</b></div><div><small>Вартість</small><b>${money(p.estimated_cost)}</b></div><div><small>Час</small><b id="liveTimer">${Number(p.duration_seconds||0).toFixed(0)} с</b></div><div><small>Токени</small><b>${(p.input_tokens||0)+(p.output_tokens||0)}</b></div></section><div class="tabs">${tabs.map(([k,v])=>`<button class="${state.tab===k?'active':''}" onclick="state.tab='${k}';render()">${v}</button>`).join('')}</div>${projectTab()}${rerunProjectDialogTpl()}${translateDialogTpl()}`);startProjectTimer();if(state.tab==='review')setTimeout(updateReviewUI,0);if(state.tab==='preview'||state.tab==='review')setTimeout(auditPreviewMedia,0)}
let projTimer;
function tickTimer(){const el=document.getElementById('liveTimer'),p=state.selected;if(!el||!p){clearInterval(projTimer);return}if(!['processing','queued'].includes(p.status)){el.textContent=`${Number(p.duration_seconds||0).toFixed(0)} с`;clearInterval(projTimer);return}const start=p.started_at?new Date(String(p.started_at).endsWith('Z')?p.started_at:p.started_at+'Z').getTime():Date.now();const sec=Math.max(0,(Date.now()-start)/1000);const m=Math.floor(sec/60),s=Math.floor(sec%60);el.textContent=m?`${m} хв ${s} с`:`${s} с`}
function startProjectTimer(){clearInterval(projTimer);tickTimer();const p=state.selected;if(p&&['processing','queued'].includes(p.status))projTimer=setInterval(tickTimer,1000)}
function projectTab(){if(state.tab==='preview')return preview();if(state.tab==='html')return htmlEditor();if(state.tab==='assets')return projectAssets();if(state.tab==='review')return reviewTab();if(state.tab==='activity')return activity();const p=state.selected;return `<section class="panel"><div class="sku-strip"><div><small>Артикул (SKU)</small><b>${p.sku?esc(p.sku):'—'}</b></div>${p.sku?`<button class="btn ghost" data-copy="${esc(p.sku)}" onclick="copyText(this)">Копіювати</button>`:''}</div><div class="summary-grid"><div><small>Категорія</small><h3>${esc(p.product_category||'Визначається')}</h3></div><div><small>Мови</small><h3>${p.languages.map(languageLabel).join(', ')}</h3></div><div><small>Формати</small><h3>${p.variants.map(x=>VARIANT[x]).join(', ')}</h3></div></div><h2>Останні етапи</h2><div class="timeline">${state.events.slice(0,8).map(e=>`<div><time>${dt(e.created_at)}</time><b>${STAGE[e.stage]||'Опрацювання'}</b><span>${esc(e.message)}</span></div>`).join('')||'<p>Подій поки немає.</p>'}</div></section>${costPanel(p)}`}
function costPanel(p){const b=p.cost_breakdown||{},rows=[['extract','Аналіз товару'],['content','Генерація тексту'],['images','Зображення']],has=rows.some(([k])=>b[k]);return `<section class="panel cost-panel"><h2>Вартість за етапами</h2>${has?`<table class="cost-table"><thead><tr><th>Етап</th><th>Обсяг</th><th>Вартість</th></tr></thead><tbody>${rows.map(([k,label])=>{const s=b[k]||{},detail=k==='images'?`${s.count||0} зобр.`:`${(s.input_tokens||0)+(s.output_tokens||0)} ток.`;return `<tr><td>${label}</td><td>${detail}</td><td>${money(s.cost)}</td></tr>`}).join('')}<tr class="cost-total"><td>Разом</td><td></td><td>${money(b.total||p.estimated_cost)}</td></tr></tbody></table>`:`<p class="muted-note">Деталізація з’явиться під час генерації. Поточна оцінка: <b>${money(p.estimated_cost)}</b>.</p>`}</section>`}
function artifactSelect(){return `<select onchange="selectArtifact(this.value)">${(state.selected.artifacts||[]).map(a=>`<option value="${a.id}" ${state.artifact?.id===a.id?'selected':''}>${a.fallback_reason?'⚠ ':''}${languageLabel(a.language)} · ${VARIANT[a.variant]} · v${a.version}${a.fallback_reason?' · аварійний шаблон':''}</option>`).join('')}</select>`}
function previewDocument(html){return `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><base href="${location.origin}/"><style>html,body{margin:0;min-height:100%;background:#fff;color:#101010}body{padding:0;font-family:Roboto,Inter,Arial,sans-serif}</style></head><body>${html}</body></html>`}
function openPreview(){if(!state.artifact?.html)return toast('Немає результату для перегляду',true);const win=window.open('about:blank','_blank');if(!win)return toast('Браузер заблокував нову вкладку',true);win.document.open();win.document.write(previewDocument(state.artifact.html));win.document.close()}
// Media health audit: HEADs every /media URL the current artifact references and
// says out loud whether invisible images are missing files (storage bug) or
// present files that fail to render (preview bug). Ends the guessing.
async function auditPreviewMedia(){const a=state.artifact;if(!a)return;const urls=[...new Set([...(a.html.match(/\/media\/[A-Za-z0-9\-]+\/[A-Za-z0-9._\-]+(?:\?t=[A-Za-z0-9]+)?/g)||[])])].slice(0,8);const key=a.language+a.variant+a.version;if(state.mediaAudit?.key===key)return renderMediaAudit();if(!urls.length){state.mediaAudit={key,results:[]};return renderMediaAudit()}
// HTTP 200 proves nothing: a zero-byte or truncated file answers 200 and renders
// as nothing. Decode each image for real and report its true dimensions.
const results=await Promise.all(urls.map(u=>new Promise(resolve=>{const img=new Image();img.onload=()=>resolve({url:u,ok:img.naturalWidth>0,w:img.naturalWidth,h:img.naturalHeight});img.onerror=()=>resolve({url:u,ok:false,w:0,h:0});img.src=u})));state.mediaAudit={key,results};renderMediaAudit()}
function renderMediaAudit(){const box=document.getElementById('mediaAudit');if(!box)return;const audit=state.mediaAudit;if(!audit||!audit.results.length){box.innerHTML='';return}const bad=audit.results.filter(x=>!x.ok);const name=u=>u.split('/').pop();box.innerHTML=bad.length?`<div class="media-audit bad"><b>Зображення не завантажуються (${bad.length} із ${audit.results.length}):</b> ${bad.map(x=>`<code>${esc(name(x.url))}</code>`).join(' ')} — файл порожній або пошкоджений. Перегенеруйте зображення.</div>`:`<div class="media-audit ok"><b>Зображення справні:</b> ${audit.results.map(x=>`<code>${esc(name(x.url))} ${x.w}×${x.h}</code>`).join(' ')}. Якщо на сторінці їх не видно — це верстка стилю, а не файли.</div>`}
function fallbackBanner(){const a=state.artifact;if(!a?.fallback_reason)return '';return `<div class="fallback-banner"><b>Це не обраний стиль.</b> AI-генерацію цієї сторінки не вдалося виконати, тому показано аварійний шаблон. Публікувати не можна — перегенеруйте проєкт.<span>Причина: ${esc(a.fallback_reason)}</span></div>`}
function preview(){if(!state.artifact)return'<div class="empty">Результат ще не створено.</div>';const variant=state.artifact.variant==='mobile'?'mobile':'desktop';return `<section class="panel preview-panel"><div class="panel-tools">${artifactSelect()}<div class="preview-hint">${variant==='mobile'?'Мобільне полотно · 480 px':'Десктопне полотно · 1240 px'}</div><button class="btn secondary" onclick="openPreview()">Відкрити окремо</button></div>${fallbackBanner()}<div id="mediaAudit"></div><div class="preview-stage"><div class="preview-canvas ${variant}"><iframe title="Попередній перегляд rich-контенту" sandbox="allow-same-origin" scrolling="yes" srcdoc="${esc(previewDocument(state.artifact.html))}"></iframe></div></div></section>`}
function htmlEditor(){if(!state.artifact)return'<div class="empty">HTML ще не створено.</div>';return `<section class="panel"><div class="panel-tools">${artifactSelect()}<button class="btn primary" onclick="saveHtml(this)">Зберегти нову версію</button></div><textarea id="htmlEditor" class="code">${esc(state.artifact.html)}</textarea></section>`}
function projectAssets(){const a=state.selected.assets||[];return `<section class="media-grid">${a.map(asset=>mediaCard(asset)).join('')||'<div class="empty">Зображень поки немає.</div>'}</section><dialog id="assetDetails"></dialog>`}
function mediaCard(a){const label=assetLabel(a);return `<article class="media-card"><div class="media-image"><img src="${esc(a.url)}" alt="${esc(label)}" loading="lazy"></div><div><span class="badge neutral">${esc(label)}</span><h3>${a.width&&a.height?`${a.width} × ${a.height}`:'Зображення'}</h3>${a.project_name?`<p class="media-project" title="${esc(a.project_name)}">${esc(a.project_name)}</p>`:''}<p>${esc(a.model==='source'?'Вихідне фото':a.model||'Джерело')}</p><small>${money(a.cost)} · ${dt(a.created_at)}</small><div class="media-actions"><button class="btn secondary" onclick="showAsset('${a.id}')">Докладніше</button><a class="btn ghost" href="${esc(a.url)}" download>Завантажити</a></div></div></article>`}
function showAsset(id){const a=state.assets.find(x=>x.id===id)||(state.selected?.assets||[]).find(x=>x.id===id);if(!a)return toast('Медіафайл не знайдено',true);const label=assetLabel(a),source=a.metadata?.source_url||a.metadata?.reference_url||'';let dlg=document.getElementById('assetDetails');if(!dlg){dlg=document.createElement('dialog');dlg.id='assetDetails';document.body.appendChild(dlg)}dlg.innerHTML=`<form method="dialog"><div class="dialog-head"><div><small class="eyebrow">МЕДІАФАЙЛ</small><h2>${esc(label)}</h2></div><button aria-label="Закрити">×</button></div><div class="asset-detail-image"><img src="${esc(a.url)}" alt="${esc(label)}"></div><div class="summary-grid"><div><small>Модель</small><h3>${esc(a.model==='source'?'Вихідне фото':a.model||'Джерело')}</h3></div><div><small>Розмір</small><h3>${a.width&&a.height?`${a.width} × ${a.height}`:'—'}</h3></div><div><small>Вартість</small><h3>${money(a.cost)}</h3></div></div>${source?`<label>Вихідний референс<input value="${esc(source)}" readonly></label>`:''}<label>Промпт<textarea rows="8" readonly>${esc(a.prompt||'Для вихідного фото промпт не використовується')}</textarea></label><div class="row"><a class="btn primary" href="${esc(a.url)}" target="_blank" rel="noopener">Відкрити оригінал</a><a class="btn secondary" href="${esc(a.url)}" download>Завантажити</a></div></form>`;dlg.showModal()}
function criticsPanel(){const critics=state.selected?.critics||[];return `<section class="panel"><div class="panel-tools"><h2>AI-перевірка якості</h2>${can('review.request_changes')||can('project.create')?`<button class="btn secondary" onclick="rerunCritic(this)">Перезапустити перевірку</button>`:''}</div><p class="critic-note">Це автоматичні евристичні перевірки: структура HTML, наявність назви й фактів товару, alt-тексти й доступність, надмірність маркетингу. Вони швидко підсвічують ризики, але <b>не гарантують якість і не замінюють ручну перевірку</b> — сприймайте оцінки як підказку, а не остаточний вердикт.</p>${critics.length?`<div class="metrics">${critics.map(c=>`<div><small>${CRITIC_LABEL[c.type]||esc(c.type)}</small><b>${Math.round(c.score)}</b></div>`).join('')}</div>${critics.filter(c=>(c.issues||[]).length).map(c=>`<div class="critic-block"><b>${CRITIC_LABEL[c.type]||esc(c.type)}</b><div class="issue-list">${c.issues.map(i=>`<div>${esc(i)}</div>`).join('')}</div></div>`).join('')||'<p class="critic-clean">Критичних зауважень не знайдено.</p>'}`:'<div class="empty">Перевірку ще не виконано.</div>'}</section>`}
const DECISION_LABEL={approve:'Схвалено',request_changes:'Запитано зміни',submit:'Надіслано на перевірку'};
function reviewChecklist(){const p=state.selected||{};return [['facts','Факти та цифри'],['images','Зображення'],['html','HTML і верстка'],...(p.languages||[]).map(l=>[`lang_${l}`,`Мова: ${languageLabel(l)}`]),...(p.variants||[]).map(v=>[`variant_${v}`,`Формат: ${VARIANT[v]||v}`])]}
function reviewHistory(){const rows=state.selected?.reviews||[];if(!rows.length)return '';return `<section class="panel"><h2>Історія перевірок</h2><div class="review-log">${rows.map(r=>{const checked=Object.entries(r.checklist||{}).filter(([,v])=>v).map(([k])=>k);return `<div class="review-entry ${r.decision}"><div class="review-entry-head"><b>${DECISION_LABEL[r.decision]||esc(r.decision)}</b><span>${esc(r.reviewer||'—')} · ${dt(r.created_at)}</span></div>${r.comment?`<p>${esc(r.comment)}</p>`:''}<small>Перевірено пунктів: ${checked.length} з ${Object.keys(r.checklist||{}).length||'—'}</small></div>`}).join('')}</div></section>`}
// Review draft lives in state, keyed to the project: flipping to Перегляд and
// back must not eat the reviewer's checkmarks or comment.
function reviewDraft(){const pid=state.selected?.id;if(!state.reviewDraft||state.reviewDraft.pid!==pid)state.reviewDraft={pid,checks:{},comment:''};return state.reviewDraft}
function reviewCheckToggle(el){reviewDraft().checks[el.value]=el.checked;updateReviewUI()}
function reviewCommentInput(el){reviewDraft().comment=el.value;updateReviewUI()}
// Checkbox clicks update the header and buttons in place: a full render() would
// reload the embedded preview iframe on every tick.
function updateReviewUI(){const d=reviewDraft(),items=reviewChecklist(),done=items.filter(([k])=>d.checks[k]).length;const anyFallback=(state.selected?.artifacts||[]).some(a=>a.fallback_reason);const counter=document.getElementById('reviewCounter');if(counter)counter.textContent=`Відмічено ${done} з ${items.length}`;const approve=document.getElementById('reviewApproveBtn');if(approve){const ready=done===items.length&&!anyFallback;approve.disabled=!ready;approve.title=anyFallback?'Серед версій є аварійний шаблон замість обраного стилю — спершу перегенеруйте':(done===items.length?'':'Схвалення можливе, коли пройдено всі пункти чекліста')}const changes=document.getElementById('reviewChangesBtn');if(changes){const hasComment=d.comment.trim().length>0;changes.disabled=!hasComment;changes.title=hasComment?'':'Опишіть у коментарі, що саме виправити'}}
function reviewTab(){const p=state.selected,canChanges=can('review.request_changes'),canApprove=can('review.approve'),canDecide=canChanges||canApprove;const d=reviewDraft();const variant=state.artifact?.variant==='mobile'?'mobile':'desktop';const changesBanner=p.status==='changes_requested'&&can('project.create')?`<section class="panel review-cta"><b>Зміни запитано.</b> Наступний крок — новий запуск із урахуванням коментаря.<button class="btn primary" onclick="document.getElementById('rerunProjectDialog').showModal()">Повторити генерацію</button></section>`:'';return `${changesBanner}${criticsPanel()}${state.artifact?`<section class="panel preview-panel"><div class="panel-tools">${artifactSelect()}<div class="preview-hint">Перевіряйте прямо тут — вкладку залишати не потрібно</div></div>${fallbackBanner()}<div id="mediaAudit"></div><div class="preview-stage review-stage"><div class="preview-canvas ${variant}"><iframe title="Перегляд для перевірки" sandbox="allow-same-origin" scrolling="yes" srcdoc="${esc(previewDocument(state.artifact.html))}"></iframe></div></div></section>`:''}<section class="panel"><div class="panel-tools"><h2>Контроль якості</h2><b id="reviewCounter" class="muted-note"></b></div><p class="critic-note">Позначайте пункти, звіряючи зі сторінкою вище. Список формується з мов і форматів цього проєкту; позначки зберігаються разом із рішенням в історії перевірок.</p><div class="review-grid">${reviewChecklist().map(([x,label])=>`<label class="check"><input type="checkbox" name="reviewcheck" value="${x}" ${d.checks[x]?'checked':''} onchange="reviewCheckToggle(this)"> ${label}</label>`).join('')}</div><label>Коментар <em>обов'язковий, якщо запитуєте зміни</em><textarea id="reviewComment" rows="4" placeholder="Що саме потрібно виправити або що перевірено" oninput="reviewCommentInput(this)">${esc(d.comment)}</textarea></label>${canDecide?`<div class="panel-tools review-actions">${canChanges?`<button id="reviewChangesBtn" class="btn danger" onclick="review('request_changes',this)">Запросити зміни</button>`:''}${canApprove?`<button id="reviewApproveBtn" class="btn primary" onclick="review('approve',this)">Схвалити</button>`:''}</div>`:'<p class="muted-note">У вас немає прав на рішення щодо перевірки.</p>'}</section>${reviewHistory()}`}
function projectActions(p){const busy=['processing','queued'].includes(p.status),stopped=['paused','cancelled','error'].includes(p.status),canQueue=can('project.create'),btns=[];if(busy&&canQueue){btns.push(`<button class="btn secondary" onclick="queueAction('pause',this)">Пауза</button>`);btns.push(`<button class="btn danger" onclick="queueAction('cancel',this)">Скасувати</button>`)}if(stopped&&canQueue)btns.push(`<button class="btn secondary" onclick="queueAction('resume',this)">Відновити</button>`);btns.push(`<button class="btn secondary" onclick="downloadArchive()">Завантажити ZIP</button>`);if(canQueue)btns.push(`<button class="btn secondary" onclick="document.getElementById('rerunProjectDialog').showModal()">Повторити генерацію</button>`);if(canQueue&&!busy)btns.push(`<button class="btn secondary" onclick="document.getElementById('translateDialog').showModal()">+ Мова</button>`);if(can('project.delete')&&!busy)btns.push(`<button class="btn danger" onclick="deleteProject(this)">Видалити</button>`);return btns.join('')}
async function queueAction(action,button){const original=button?.textContent;if(button){button.disabled=true;button.textContent='…'}try{await api(`/api/projects/${state.selected.id}/queue`,{method:'POST',body:JSON.stringify({action})});toast(action==='pause'?'Проєкт призупинено':action==='cancel'?'Проєкт скасовано':'Проєкт повернуто в чергу');await refreshSelected();state.projects=await api('/api/projects');render()}catch(x){toast(x.message,true);if(button){button.disabled=false;button.textContent=original}}}
async function deleteProject(button){if(!confirm('Видалити проєкт разом з усіма версіями, зображеннями та історією? Дію не можна скасувати.'))return;if(button)button.disabled=true;try{await api(`/api/projects/${state.selected.id}`,{method:'DELETE'});toast('Проєкт видалено');state.selected=null;state.projects=await api('/api/projects');render()}catch(x){toast(x.message,true);if(button)button.disabled=false}}
async function rerunCritic(button){const original=button?.textContent;if(button){button.disabled=true;button.textContent='Перевірка…'}try{await api(`/api/projects/${state.selected.id}/critic`,{method:'POST',body:JSON.stringify({auto_fix:false})});await refreshSelected();toast('Перевірку якості оновлено');render()}catch(x){toast(x.message,true)}finally{if(button){button.disabled=false;button.textContent=original}}}
function activity(){return `<section class="panel"><h2>Історія проекта</h2><div class="timeline">${state.events.map(e=>`<div><time>${dt(e.created_at)}</time><b>${STAGE[e.stage]||'Опрацювання'}</b><span>${esc(e.message)}</span></div>`).join('')}</div></section>`}
function translateDialogTpl(){const p=state.selected;if(!p)return '';const have=new Set(String(p.languages||'').split(',').map(x=>x.trim()).filter(Boolean));const src=(String(p.languages||'ua').split(',')[0]||'ua').trim();const quick=['pl','en','de','cs','ro','bg'].filter(x=>!have.has(x));return `<dialog id="translateDialog"><form onsubmit="translateProject(event)"><div class="dialog-head"><div><small class="eyebrow">ДОДАТИ МОВУ</small><h2>Переклад готової версії</h2></div><button type="button" aria-label="Закрити" onclick="translateDialog.close()">×</button></div><p class="muted-note">Не повторний запуск: перекладається лише текст останніх версій ${src.toUpperCase()} — верстка, стилі й зображення лишаються байт-у-байт. Це найдешевший спосіб додати мову (~вартість тексту, без зображень).</p><label>Мова<div class="row" style="flex-wrap:wrap;gap:8px">${quick.map(code=>`<label class="check" style="margin:0"><input type="radio" name="language" value="${code}"> ${LANG[code]||code.toUpperCase()}</label>`).join('')}</div></label><label>Або код мови (ISO/BCP-47)<input name="custom_language" placeholder="напр. lt, lv, hu, en-GB" spellcheck="false"></label><button class="btn primary">Перекласти</button></form></dialog>`}
async function translateProject(e){e.preventDefault();const f=new FormData(e.target);const language=(f.get('custom_language')||'').trim()||f.get('language');if(!language)return toast('Оберіть мову',true);try{const r=await api(`/api/projects/${state.selected.id}/translate`,{method:'POST',body:JSON.stringify({language})});translateDialog.close();toast(`Переклад на ${String(r.language).toUpperCase()} запущено — стежте в Історії`);await refreshSelected();render()}catch(x){toast(x.message,true)}}
function rerunProjectDialogTpl(){const p=state.selected||{},current=p.style_id,variants=p.variants||['desktop','mobile'];return `<dialog id="rerunProjectDialog"><form onsubmit="rerun(event)"><div class="dialog-head"><div><small class="eyebrow">ПОВТОРНА ГЕНЕРАЦІЯ</small><h2>Налаштуйте новий запуск</h2></div><button type="button" aria-label="Закрити" onclick="document.getElementById('rerunProjectDialog').close()">×</button></div><label>Стиль для нової генерації<select name="style_id" required>${state.styles.map(s=>`<option value="${s.id}" ${s.id===current?'selected':''}>${esc(s.name)}${s.is_default?' · базовий':''}</option>`).join('')}</select></label>${languagePicker(p.languages||['ua','ru'])}<fieldset><legend>Формати</legend><div class="language-grid"><label class="check"><input type="checkbox" name="variant" value="desktop" ${variants.includes('desktop')?'checked':''}> Десктоп</label><label class="check"><input type="checkbox" name="variant" value="mobile" ${variants.includes('mobile')?'checked':''}> Мобільна</label></div></fieldset>${reuseImagesField()}<p class="dialog-note">Попередні HTML-версії залишаться в історії. Текст буде створено заново за обраним стилем, мовами й форматами.</p><button class="btn primary">Запустити повторно</button></form></dialog>`}
function reuseImagesField(){const imgs=(state.selected?.assets||[]).filter(a=>a.kind==='image'&&/^(hero|feature)/.test(a.label||''));if(!imgs.length)return '';const cost=imgs.filter(a=>Number(a.cost)>0).reduce((s,a)=>s+Number(a.cost||0),0);return `<fieldset class="language-fieldset"><legend>Зображення</legend><label class="check"><input type="checkbox" name="reuse_images" checked> Використати наявні зображення (${imgs.length} шт.)</label><p class="muted-note" style="margin-top:8px">Зніміть галочку, щоб створити зображення заново${cost?` — це додасть близько ${money(cost)} до вартості`:''}. З галочкою перегенерується лише текст: швидше й без витрат на зображення.</p></fieldset>`}
async function rerun(e){e.preventDefault();const form=e.currentTarget,button=e.submitter,original=button?.textContent;if(button){button.disabled=true;button.textContent='Запуск…'}try{const data=new FormData(form),payload={style_id:data.get('style_id'),languages:collectLanguages(form),variants:[...form.querySelectorAll('[name=variant]:checked')].map(x=>x.value),reuse_images:!!form.querySelector('[name=reuse_images]:checked')};await api(`/api/projects/${state.selected.id}/run`,{method:'POST',body:JSON.stringify(payload)});form.closest('dialog').close();toast('Генерацію запущено з новими параметрами');await refreshSelected();state.projects=await api('/api/projects');render()}catch(x){toast(x.message,true)}finally{if(button){button.disabled=false;button.textContent=original}}}
async function downloadArchive(){if(!state.selected)return;try{toast('Підготовка ZIP-архіву…');const response=await fetch(`/api/projects/${state.selected.id}/archive`,{headers:{Authorization:`Bearer ${state.token}`}});if(!response.ok){const text=await response.text();let detail=text;try{detail=JSON.parse(text)?.detail||text}catch{}throw Error(detail||`HTTP ${response.status}`)}const blob=await response.blob(),disposition=response.headers.get('content-disposition')||'',match=disposition.match(/filename="([^"]+)"/),filename=match?.[1]||'artline-rich.zip',url=URL.createObjectURL(blob),link=document.createElement('a');link.href=url;link.download=filename;document.body.appendChild(link);link.click();link.remove();setTimeout(()=>URL.revokeObjectURL(url),3000);toast('Архів завантажено')}catch(x){toast(x.message,true)}}
async function saveHtml(button){if(pendingSave)return;pendingSave=true;const original=button?.textContent;if(button){button.disabled=true;button.textContent='Збереження…'}try{const editor=document.getElementById('htmlEditor');const d=await api(`/api/artifacts/${state.artifact.id}`,{method:'PUT',body:JSON.stringify({html:editor.value})});await refreshSelected();state.artifact=(state.selected.artifacts||[]).find(x=>x.id===d.id)||d;toast(`Збережено версію v${d.version}`);render()}catch(x){toast(x.message,true)}finally{pendingSave=false;if(button){button.disabled=false;button.textContent=original}}}
async function review(decision,button){if(pendingSave)return;pendingSave=true;const original=button?.textContent;if(button){button.disabled=true;button.textContent='Збереження…'}try{const d=reviewDraft();const checks=Object.fromEntries(reviewChecklist().map(([k])=>[k,!!d.checks[k]]));const comment=d.comment||'';const d2=await api(`/api/projects/${state.selected.id}/review`,{method:'POST',body:JSON.stringify({decision,comment,checklist:checks})});toast(d2.message||'Рішення збережено');state.reviewDraft=null;await refreshSelected();render()}catch(x){toast(x.message,true)}finally{pendingSave=false;if(button){button.disabled=false;button.textContent=original}}}
function stylesPage(){const s=state.styleEdit||state.styles[0]||{};shell(`<header class="pagehead"><div><small class="eyebrow">РУШІЙ СТИЛІВ</small><h1>Стилі</h1><p>Створюйте, покращуйте та версіонуйте дизайн-код rich-контенту.</p></div><div><button class="btn secondary" onclick="styleGenerator.showModal()">Згенерувати стиль</button><button class="btn primary" onclick="state.styleEdit={};state.styleTab='general';render()">+ Новий стиль</button></div></header><section class="style-shell"><div class="style-list">${state.styles.map(x=>`<button class="${s.id===x.id?'active':''}" onclick="state.styleEdit=state.styles.find(y=>y.id==='${x.id}');render()"><b>${esc(x.name)}</b><small>${[x.is_default?'За замовчуванням':'',MANAGED_STYLE_NAMES.includes(x.name)?'Керований':'Власний'].filter(Boolean).join(' · ')}</small></button>`).join('')}</div><div><div class="subtabs">${[['general','Основне'],['html','HTML'],['images','Зображення'],['quality','Якість'],['preview','Перегляд']].map(([k,v])=>`<button class="${state.styleTab===k?'active':''}" onclick="state.styleTab='${k}';render()">${v}</button>`).join('')}</div>${styleEditor(s)}</div></section>${styleGeneratorDialog()}`)}
function styleEditor(s){const score=s.score||{};if(state.styleTab==='preview'){if(s.id&&state.stylePreviewFor!==s.id){state.stylePreviewFor=s.id;state.stylePreview=null;state.stylePreviewSource='';loadStylePreview(s.id)}const noteMap={demo:'Швидка демонстрація макета без AI — однакова для всіх стилів. Натисніть «Згенерувати AI-приклад», щоб побачити сторінку саме за цим стилем.',saved:'Збережений приклад цього стилю.',generated:'AI-приклад, згенерований за цим стилем на демо-товарі.'};return `<section class="panel"><div class="panel-tools"><h2>Демонстрація стилю</h2>${s.id&&can('style.manage')?`<button class="btn primary" onclick="generateStylePreview('${s.id}',this)">Згенерувати AI-приклад</button>`:''}</div>${state.stylePreview?`<div class="preview-stage style-demo"><div class="preview-canvas desktop"><iframe title="Демонстрація стилю" sandbox="allow-same-origin" scrolling="yes" srcdoc="${esc(previewDocument(state.stylePreview))}"></iframe></div></div><p class="muted-note">${noteMap[state.stylePreviewSource]||''}</p>`:s.id?'<div class="empty">Завантаження демонстрації…</div>':'<div class="empty">Спершу збережіть стиль.</div>'}</section>`}if(state.styleTab==='quality')return `<section class="panel"><div class="panel-tools"><h2>Якість стилю</h2><div class="row"><button class="btn secondary" onclick="analyzeStyle()">Перевірити стиль</button>${s.id?`<button class="btn ghost" onclick="loadStyleVersions('${s.id}')">Історія версій</button>`:''}</div></div><div class="metrics"><div><small>Узгодженість</small><b>${score.consistency||'—'}</b></div><div><small>Читабельність</small><b>${score.readability||'—'}</b></div><div><small>Відповідність ARTLINE</small><b>${score.brand_fit||'—'}</b></div></div>${state.styleIssues.length?`<div class="issue-list">${state.styleIssues.map(x=>`<div>${esc(x)}</div>`).join('')}</div>`:''}${state.styleVersions.length?`<div class="version-list">${state.styleVersions.map(v=>`<button onclick="restoreStyleVersion(${v.version})"><b>v${v.version}</b><small>${dt(v.created_at)}</small></button>`).join('')}</div>`:''}${s.id?`<label>Що покращити<textarea id="improveInstructions" rows="5" placeholder="Наприклад: зробити Hero преміальнішим і зменшити візуальний шум"></textarea></label><button class="btn primary" onclick="improveStyle('${s.id}')">Покращити стиль через AI</button>`:''}</section>`;return `<form class="panel style-form" onsubmit="saveStyle(event)" oninput="scheduleStyleAutosave(event)" onchange="scheduleStyleAutosave(event)"><input type="hidden" name="id" value="${esc(s.id||'')}">${state.styleTab==='general'?`<label>Назва<input name="name" value="${esc(s.name||'')}" required></label><label>Опис<textarea name="description" rows="5">${esc(s.description||'')}</textarea></label><label class="check"><input type="checkbox" name="is_default" ${s.is_default?'checked':''}> Використовувати за замовчуванням</label>`:''}${state.styleTab==='html'?`<label>Єдиний Style Prompt<textarea name="prompt" rows="24">${esc(s.prompt||'')}</textarea></label>`:''}${state.styleTab==='images'?`<label>Промпт Hero <em>необов’язково</em><textarea name="hero_prompt" rows="10">${esc(s.hero_prompt||'')}</textarea></label><label>Промпт Feature <em>необов’язково</em><textarea name="feature_prompt" rows="10">${esc(s.feature_prompt||'')}</textarea></label><label>Негативний промпт<textarea name="negative_prompt" rows="7">${esc(s.negative_prompt||'')}</textarea></label>`:''}<div class="style-savebar"><span id="styleSaveStatus">${s.id?'Усі зміни зберігаються автоматично':'Заповніть поля та створіть стиль'}</span><div class="row">${s.id?styleDeleteButton(s):`<button class="btn primary">Створити стиль</button>`}</div></div></form>`}
// Always render the delete control, disabled with the reason — a button that simply
// vanishes leaves people hunting for it.
function styleDeleteButton(s){if(!can('style.manage'))return '';let why='';if(MANAGED_STYLE_NAMES.includes(s.name))why='Керований стиль — його відновлює система під час запуску';else if(s.is_default)why='Спершу призначте інший стиль за замовчуванням';return why?`<button type="button" class="btn danger" disabled title="${esc(why)}">Видалити стиль</button><span class="delete-why">${esc(why)}</span>`:`<button type="button" class="btn danger" onclick="deleteStyle('${s.id}')">Видалити стиль</button>`}
async function loadStylePreview(id){try{const d=await api(`/api/styles/${id}/preview`);if(state.stylePreviewFor!==id)return;state.stylePreview=d.html;state.stylePreviewSource=d.source;render()}catch(x){toast(x.message,true)}}
async function generateStylePreview(id,button){const original=button?.textContent;if(button){button.disabled=true;button.textContent='Генерація…'}try{const d=await api(`/api/styles/${id}/preview`,{method:'POST'});state.stylePreviewFor=id;state.stylePreview=d.html;state.stylePreviewSource=d.source;state.styles=await api('/api/styles');if(state.styleEdit?.id===id)state.styleEdit=state.styles.find(x=>x.id===id)||state.styleEdit;toast(d.source==='generated'?'AI-приклад згенеровано та збережено':'AI недоступний — показано демо-шаблон',d.source!=='generated');render()}catch(x){toast(x.message,true)}finally{if(button){button.disabled=false;button.textContent=original}}}
async function deleteStyle(id){if(!confirm('Видалити стиль? Проєкти, що його використовують, буде переприв’язано до базового стилю.'))return;try{const d=await api(`/api/styles/${id}`,{method:'DELETE'});state.styles=await api('/api/styles');state.styleEdit=state.styles.find(x=>x.is_default)||state.styles[0]||null;toast(d.reassigned_projects?`Стиль видалено, проєктів переприв’язано: ${d.reassigned_projects}`:'Стиль видалено');render()}catch(x){toast(x.message,true)}}
function collectStyleForm(f){const base=state.styleEdit||state.styles[0]||{};return {name:f.get('name')||base.name||'Новий стиль',description:f.get('description')??base.description??'',prompt:f.get('prompt')??base.prompt??'',hero_prompt:f.get('hero_prompt')??base.hero_prompt??'',feature_prompt:f.get('feature_prompt')??base.feature_prompt??'',negative_prompt:f.get('negative_prompt')??base.negative_prompt??'',score:base.score||{},preview_html:base.preview_html||'',is_default:state.styleTab==='general'?f.get('is_default')==='on':!!base.is_default}}
function styleSaveMessage(text,bad=false){const node=document.getElementById('styleSaveStatus');if(node){node.textContent=text;node.classList.toggle('bad',bad)}}
function scheduleStyleAutosave(e){const form=e.currentTarget,id=new FormData(form).get('id'),payload=collectStyleForm(new FormData(form));state.styleEdit={...(state.styleEdit||{}),...payload};if(!id)return;styleSaveRevision+=1;stylePendingSave={id,payload,revision:styleSaveRevision};clearTimeout(styleSaveTimer);styleSaveMessage('Є незбережені зміни…');styleSaveTimer=setTimeout(flushStyleAutosave,850)}
async function flushStyleAutosave(){if(styleSaveBusy||!stylePendingSave)return;const item=stylePendingSave;stylePendingSave=null;styleSaveBusy=true;styleSaveMessage('Збереження…');try{const saved=await api(`/api/styles/${item.id}`,{method:'PUT',body:JSON.stringify(item.payload)});state.styles=state.styles.map(x=>x.id===saved.id?saved:x);if(item.revision===styleSaveRevision)state.styleEdit=saved;styleSaveMessage('Збережено автоматично')}catch(x){styleSaveMessage('Помилка збереження',true);toast(x.message,true)}finally{styleSaveBusy=false;if(stylePendingSave){clearTimeout(styleSaveTimer);styleSaveTimer=setTimeout(flushStyleAutosave,300)}}}
async function saveStyle(e){e.preventDefault();if(pendingSave)return;pendingSave=true;const button=e.submitter;const original=button?.textContent;if(button){button.disabled=true;button.textContent='Збереження…'}const f=new FormData(e.target),id=f.get('id'),payload=collectStyleForm(f);try{const d=await api(id?`/api/styles/${id}`:'/api/styles',{method:id?'PUT':'POST',body:JSON.stringify(payload)});state.styles=await api('/api/styles');state.styleEdit=state.styles.find(x=>x.id===(d.id||id))||state.styles[0];toast('Стиль збережено');render()}catch(x){toast(x.message,true)}finally{pendingSave=false;if(button){button.disabled=false;button.textContent=original}}}
function styleGeneratorDialog(){return `<dialog id="styleGenerator"><form onsubmit="generateStyle(event)"><div class="dialog-head"><div><small class="eyebrow">AI-ГЕНЕРАТОР СТИЛІВ</small><h2>Створити дизайн-стиль</h2></div><button type="button" aria-label="Закрити" onclick="styleGenerator.close()">×</button></div><label>Назва<input name="name" value="ARTLINE Premium" required></label><label>Опис бажаного результату<textarea name="brief" rows="8" placeholder="Категорія товару, настрій, структура блоків, рівень преміальності, обмеження..."></textarea></label><div class="form-grid"><label>Категорія<input name="category" placeholder="3D-принтери, енергетика, ігрові ПК..."></label><label>Настрій<input name="mood" placeholder="Преміальний, технічний, мінімалістичний..."></label></div><label>URL-референс <em>необов’язково</em><input name="reference_url" type="url"></label><label>Модель<input name="model" list="styleModels" value="${esc(state.models.default_text_model||'')}">${dataList('styleModels',state.models.text_models||[])}</label><button class="btn primary">Згенерувати</button></form></dialog>`}
async function generateStyle(e){e.preventDefault();const f=new FormData(e.target),button=e.submitter,original=button?.textContent;if(button){button.disabled=true;button.textContent='Генерація…'}try{const request=Object.fromEntries(f);request.brief=[request.brief,request.category&&`Category: ${request.category}`,request.mood&&`Mood: ${request.mood}`].filter(Boolean).join('\n');const d=await api('/api/styles/generate',{method:'POST',body:JSON.stringify(request)}),payload={name:f.get('name'),description:d.description||'',prompt:d.style_prompt||'',hero_prompt:d.hero_prompt||'',feature_prompt:d.feature_prompt||'',negative_prompt:d.negative_prompt||'',score:d.score||{},preview_html:d.preview_html||'',is_default:false},saved=await api('/api/styles',{method:'POST',body:JSON.stringify(payload)});state.styles=await api('/api/styles');state.styleEdit=state.styles.find(x=>x.id===saved.id)||saved;styleGenerator.close();state.styleTab='preview';toast('Стиль згенеровано та збережено');render()}catch(x){toast(x.message,true)}finally{if(button){button.disabled=false;button.textContent=original}}}
async function analyzeStyle(){const s=state.styleEdit||{};try{const d=await api('/api/styles/analyze',{method:'POST',body:JSON.stringify({prompt:s.prompt||'',hero_prompt:s.hero_prompt||'',feature_prompt:s.feature_prompt||'',negative_prompt:s.negative_prompt||''})}),updated={...s,score:d.score};state.styleEdit=updated;state.styleIssues=d.issues||[];if(s.id){const saved=await api(`/api/styles/${s.id}`,{method:'PUT',body:JSON.stringify({name:updated.name,description:updated.description||'',prompt:updated.prompt||'',hero_prompt:updated.hero_prompt||'',feature_prompt:updated.feature_prompt||'',negative_prompt:updated.negative_prompt||'',score:updated.score||{},preview_html:updated.preview_html||'',is_default:!!updated.is_default})});state.styles=state.styles.map(x=>x.id===saved.id?saved:x);state.styleEdit=saved}toast(d.ready?'Стиль перевірено та збережено':'Рекомендації збережено',!d.ready);render()}catch(x){toast(x.message,true)}}
async function loadStyleVersions(id){try{state.styleVersions=await api(`/api/styles/${id}/versions`);render()}catch(x){toast(x.message,true)}}
async function restoreStyleVersion(version){const v=state.styleVersions.find(x=>x.version===version),s=state.styleEdit;if(!v||!s?.id)return;try{const payload={name:s.name,description:s.description||'',prompt:v.prompt||'',hero_prompt:v.hero_prompt||'',feature_prompt:v.feature_prompt||'',negative_prompt:s.negative_prompt||'',score:s.score||{},preview_html:s.preview_html||'',is_default:!!s.is_default},saved=await api(`/api/styles/${s.id}`,{method:'PUT',body:JSON.stringify(payload)});state.styles=state.styles.map(x=>x.id===saved.id?saved:x);state.styleEdit=saved;state.styleTab='html';toast(`Версію v${version} відновлено та збережено`);render()}catch(x){toast(x.message,true)}}
async function improveStyle(id){try{const d=await api(`/api/styles/${id}/improve`,{method:'POST',body:JSON.stringify({instructions:improveInstructions.value,model:state.models.default_text_model})}),s=state.styleEdit,payload={name:s.name,description:d.description||s.description||'',prompt:d.style_prompt||s.prompt||'',hero_prompt:d.hero_prompt||s.hero_prompt||'',feature_prompt:d.feature_prompt||s.feature_prompt||'',negative_prompt:d.negative_prompt||s.negative_prompt||'',score:d.score||s.score||{},preview_html:d.preview_html||s.preview_html||'',is_default:!!s.is_default},saved=await api(`/api/styles/${id}`,{method:'PUT',body:JSON.stringify(payload)});state.styles=state.styles.map(x=>x.id===saved.id?saved:x);state.styleEdit=saved;state.styleTab='preview';toast('Покращену версію збережено');render()}catch(x){toast(x.message,true)}}
function mediaPage(){const filters=[['all','Усі джерела'],['generated','Згенеровані AI'],['source','Вихідні фото товару'],['custom','Власні фото']],roles=[['all','Усі ролі'],['hero','Hero'],['feature','Feature'],['reference','Референси'],['other','Інші']],sorts=[['created_desc','Спочатку нові'],['created_asc','Спочатку старі'],['size_desc','Найбільша роздільність'],['cost_desc','Найвища вартість'],['project_asc','За назвою проєкту'],['role_asc','За типом зображення']],projects=[...new Map(state.assets.filter(x=>x.project_id).map(x=>[x.project_id,x.project_name||x.project_id])).entries()].sort((a,b)=>String(a[1]).localeCompare(String(b[1]),'uk'));let rows=[...state.assets];if(state.mediaFilter!=='all')rows=rows.filter(x=>assetCategory(x)===state.mediaFilter);if(state.mediaRole!=='all')rows=rows.filter(x=>assetRole(x)===state.mediaRole);if(state.mediaProject!=='all')rows=rows.filter(x=>x.project_id===state.mediaProject);const q=state.mediaSearch.trim().toLowerCase();if(q)rows=rows.filter(x=>[x.project_name,assetLabel(x),x.model,x.prompt].some(v=>String(v||'').toLowerCase().includes(q)));rows.sort((a,b)=>{if(state.mediaSort==='created_asc')return new Date(a.created_at)-new Date(b.created_at);if(state.mediaSort==='size_desc')return Number(b.width||0)*Number(b.height||0)-Number(a.width||0)*Number(a.height||0);if(state.mediaSort==='cost_desc')return Number(b.cost||0)-Number(a.cost||0);if(state.mediaSort==='project_asc')return String(a.project_name||'').localeCompare(String(b.project_name||''),'uk');if(state.mediaSort==='role_asc')return assetRole(a).localeCompare(assetRole(b))||new Date(b.created_at)-new Date(a.created_at);return new Date(b.created_at)-new Date(a.created_at)});shell(`<header class="pagehead"><div><small class="eyebrow">МЕДІАТЕКА</small><h1>Медіа</h1><p>Знаходьте зображення за проєктом, призначенням, джерелом і параметрами.</p></div></header><section class="toolbar media-toolbar advanced"><input placeholder="Пошук за проєктом, моделлю або промптом" value="${esc(state.mediaSearch)}" oninput="state.mediaSearch=this.value;render()"><select onchange="state.mediaFilter=this.value;render()">${filters.map(([value,label])=>`<option value="${value}" ${state.mediaFilter===value?'selected':''}>${label}</option>`).join('')}</select><select onchange="state.mediaRole=this.value;render()">${roles.map(([value,label])=>`<option value="${value}" ${state.mediaRole===value?'selected':''}>${label}</option>`).join('')}</select><select onchange="state.mediaProject=this.value;render()"><option value="all">Усі проєкти</option>${projects.map(([id,name])=>`<option value="${esc(id)}" ${state.mediaProject===id?'selected':''}>${esc(name)}</option>`).join('')}</select><select onchange="state.mediaSort=this.value;render()">${sorts.map(([value,label])=>`<option value="${value}" ${state.mediaSort===value?'selected':''}>${label}</option>`).join('')}</select><b>${rows.length} файлів</b></section><section class="media-grid">${rows.map(mediaCard).join('')||'<div class="empty">За обраними фільтрами зображень немає.</div>'}</section><dialog id="assetDetails"></dialog>`) }
function usagePage(){const q=state.usage.quality||{};const rate=v=>v==null?'—':`${v}%`;const periods=[[7,'7 днів'],[30,'30 днів'],[90,'90 днів'],[365,'Рік'],[0,'Весь час']];const activeUser=(state.usage.by_user||[]).find(u=>u.user_id===state.usageUser);shell(`<header class="pagehead"><div><small class="eyebrow">ВИКОРИСТАННЯ</small><h1>Використання</h1><p>Час, токени, вартість і довіра до результату${activeUser?` · фільтр: <b>${esc(activeUser.name)}</b>`:''}.</p></div><div><select onchange="setUsageFilter(this.value,null)">${periods.map(([v,l])=>`<option value="${v}" ${state.usageDays===v?'selected':''}>${l}</option>`).join('')}</select>${state.usageUser?`<button class="btn secondary" onclick="setUsageFilter(null,'')">Зняти фільтр користувача</button>`:''}</div></header><section class="metrics large"><div><small>Загальна вартість</small><b>${money(state.usage.total_cost)}</b></div><div><small>Проєкти</small><b>${state.usage.projects||0}</b></div><div><small>Вхідні токени</small><b>${state.usage.input_tokens||0}</b></div><div><small>Вихідні токени</small><b>${state.usage.output_tokens||0}</b></div><div><small>Зображення</small><b>${state.usage.images||0}</b></div></section><section class="panel"><h2>Динаміка витрат</h2>${usageChart()}</section>${usageUserTable()}<section class="panel quality-panel"><h2>Якість результату</h2><p class="critic-note">Головний показник корисності інструмента: скільки перевірених сторінок команда схвалює і як часто доводиться правити HTML руками. Якщо частка схвалень падає нижче ~70% — генерація потребує уваги.</p><div class="metrics"><div><small>Схвалено з перевірених</small><b class="${(q.approve_rate??100)<70?'quality-bad':''}">${rate(q.approve_rate)}</b></div><div><small>Схвалено без запиту змін</small><b>${rate(q.clean_approve_rate)}</b></div><div><small>Перевірено проєктів</small><b>${q.reviewed_projects||0}</b></div><div><small>Ручних правок HTML</small><b>${q.manual_html_edits||0}</b></div><div><small>Згенеровано сторінок</small><b>${q.generated_pages||0}</b></div></div></section>`)}
function usersPage(){shell(`<header class="pagehead"><div><small class="eyebrow">ДОСТУП</small><h1>Користувачі</h1><p>Створюйте облікові записи безпосередньо або запрошуйте за посиланням.</p></div><div><button class="btn secondary" onclick="inviteDialog.showModal()">Запросити</button><button class="btn primary" onclick="createUserDialog.showModal()">+ Створити користувача</button></div></header><section class="panel table-wrap"><table><thead><tr><th>Користувач</th><th>Роль</th><th>Активний</th><th>Останній вхід</th><th>Дії</th></tr></thead><tbody>${state.users.map(u=>`<tr><td><b>${esc(u.name||u.email)}</b>${u.is_root?'<span class="cat-chip" style="margin-left:6px">Головний</span>':''}<small>${esc(u.email)}</small></td><td>${u.is_root?`<span class="badge approved">${ROLE_LABEL[u.role]}</span>`:`<select onchange="updateUser('${u.id}','role',this.value)">${['admin','editor','reviewer','viewer'].map(r=>`<option value="${r}" ${u.role===r?'selected':''}>${ROLE_LABEL[r]}</option>`).join('')}</select>`}</td><td><input type="checkbox" ${u.active?'checked':''} ${u.is_root?'disabled':''} onchange="updateUser('${u.id}','active',this.checked)"></td><td title="${dt(u.last_login_at)}">${rel(u.last_login_at)}</td><td><div class="row">${u.is_root?'<small class="muted-note">Керується через .env</small>':`<button class="btn ghost" onclick="openPerms('${u.id}')">Доступи</button><button class="btn ghost" onclick="resetPassword('${u.id}')">Пароль</button>${u.id!==state.me.id?`<button class="btn danger" onclick="deleteUser('${u.id}')">Видалити</button>`:''}`}</div></td></tr>`).join('')}</tbody></table></section>${userDialogs()}`)}
function userDialogs(){return `<dialog id="createUserDialog"><form onsubmit="createUser(event)"><div class="dialog-head"><h2>Створити користувача</h2><button type="button" aria-label="Закрити" onclick="createUserDialog.close()">×</button></div><label>Ім’я<input name="name" required></label><label>Email<input name="email" type="email" required></label><label>Пароль<input name="password" type="password" minlength="8" required></label><label>Роль<select name="role"><option value="editor">Редактор</option><option value="reviewer">Рев’юер</option><option value="viewer">Перегляд</option><option value="admin">Адміністратор</option></select></label><button class="btn primary">Створити</button></form></dialog><dialog id="inviteDialog"><form onsubmit="inviteUser(event)"><div class="dialog-head"><h2>Запросити користувача</h2><button type="button" aria-label="Закрити" onclick="inviteDialog.close()">×</button></div><label>Email<input name="email" type="email" required></label><label>Роль<select name="role"><option value="editor">Редактор</option><option value="reviewer">Рев’юер</option><option value="viewer">Перегляд</option><option value="admin">Адміністратор</option></select></label><button class="btn primary">Створити посилання</button></form></dialog>`}
async function createUser(e){e.preventDefault();try{await api('/api/users',{method:'POST',body:JSON.stringify(Object.fromEntries(new FormData(e.target)))});createUserDialog.close();state.users=await api('/api/users');toast('Користувача створено');render()}catch(x){toast(x.message,true)}}
async function inviteUser(e){e.preventDefault();try{const d=await api('/api/users/invites',{method:'POST',body:JSON.stringify(Object.fromEntries(new FormData(e.target)))});inviteDialog.close();prompt('Посилання для реєстрації',location.origin+d.register_path)}catch(x){toast(x.message,true)}}
async function updateUser(id,key,value){await api(`/api/users/${id}`,{method:'PATCH',body:JSON.stringify({[key]:value})});state.users=await api('/api/users');render()}
async function resetPassword(id){const password=prompt('Новий пароль (щонайменше 8 символів)');if(!password)return;try{await api(`/api/users/${id}/password`,{method:'POST',body:JSON.stringify({password})});toast('Пароль оновлено')}catch(x){toast(x.message,true)}}
async function deleteUser(id){if(!confirm('Видалити користувача?'))return;try{await api(`/api/users/${id}`,{method:'DELETE'});state.users=await api('/api/users');toast('Користувача видалено');render()}catch(x){toast(x.message,true)}}
async function openPerms(id){const u=state.users.find(x=>x.id===id);if(!u)return;try{if(!state.permCatalog)state.permCatalog=await api('/api/permissions')}catch(x){return toast(x.message,true)}const cat=state.permCatalog,defaults=new Set(cat.role_defaults[u.role]||[]),eff=new Set(u.permissions||[]);let dlg=document.getElementById('permsDialog');if(!dlg){dlg=document.createElement('dialog');dlg.id='permsDialog';document.body.appendChild(dlg)}dlg.innerHTML=`<form onsubmit="savePerms(event,'${u.id}')"><div class="dialog-head"><div><small class="eyebrow">ДОСТУПИ</small><h2>${esc(u.name||u.email)}</h2></div><button type="button" aria-label="Закрити" onclick="permsDialog.close()">×</button></div><p class="muted-note">Роль <b>${ROLE_LABEL[u.role]||u.role}</b> дає базовий набір прав (позначено «за роллю»). Тут можна точково додати або прибрати окремі права саме цьому користувачу.</p><div class="perm-list">${cat.permissions.map(p=>`<label class="check perm-row"><input type="checkbox" name="perm" value="${p.key}" ${eff.has(p.key)?'checked':''}><span><b>${esc(p.label)}</b>${defaults.has(p.key)?'<em class="perm-default">за роллю</em>':''}</span></label>`).join('')}</div><button class="btn primary">Зберегти доступи</button></form>`;dlg.showModal()}
async function savePerms(e,id){e.preventDefault();const u=state.users.find(x=>x.id===id),defaults=new Set(state.permCatalog.role_defaults[u.role]||[]),form=e.currentTarget;const checked=new Set([...form.querySelectorAll('[name=perm]:checked')].map(x=>x.value));const grant=[],revoke=[];state.permCatalog.permissions.forEach(p=>{const on=checked.has(p.key),def=defaults.has(p.key);if(on&&!def)grant.push(p.key);if(!on&&def)revoke.push(p.key)});try{await api(`/api/users/${id}/permissions`,{method:'PATCH',body:JSON.stringify({grant,revoke})});state.users=await api('/api/users');if(id===state.me.id)state.me=await api('/api/me');form.closest('dialog').close();toast('Доступи оновлено');render()}catch(x){toast(x.message,true)}}
const fmtBytes=n=>{if(!n)return '0 Б';const u=['Б','КБ','МБ','ГБ','ТБ'];let i=0;while(n>=1024&&i<u.length-1){n/=1024;i++}return `${n.toFixed(n>=10||i===0?0:1)} ${u[i]}`};
const okBadge=(ok,yes='Працює',no='Недоступно')=>`<span class="badge ${ok?'approved':'error'}">${ok?yes:no}</span>`;
const isReasoning=(x,list)=>(list||[]).includes(x);
function modelList(items,reasoning){return `<div class="model-list">${(items||[]).map(x=>`<code class="${isReasoning(x,reasoning)?'is-reasoning':''}" ${isReasoning(x,reasoning)?'title="Витрачає токени на приховані міркування"':''}>${esc(x)}</code>`).join('')||'<small class="muted-note">Порожньо.</small>'}</div>`}
function modelNotes(){const m=state.models||{},gone=m.unavailable||[],np=m.unpriced||[];return `${gone.length?`<p class="critic-note">Налаштовані, але недоступні на цьому ключі: ${gone.map(x=>`<code>${esc(x)}</code>`).join(' ')}. Приберіть їх із <code>.env</code> або перевірте доступ у обліковому записі.</p>`:''}${np.length?`<p class="critic-note">Без відомої ціни: ${np.map(x=>`<code>${esc(x)}</code>`).join(' ')}. Генерація працює, але оцінка вартості для них буде приблизною — ${state.me?.is_root?'додайте тариф у <code>TEXT_PRICING_JSON</code> / <code>IMAGE_PRICING_JSON</code>.':'зверніться до адміністратора.'}</p>`:''}`}
function settingsPage(){const s=state.system;shell(`<header class="pagehead"><div><small class="eyebrow">НАЛАШТУВАННЯ</small><h1>Налаштування</h1><p>Стан системи, конфігурація та доступні моделі. ${state.me?.is_root?'Ключі змінюються тут, решта — у <code>.env</code> на сервері.':'Конфігурацією керує адміністратор.'}</p></div><div><button class="btn secondary" onclick="reloadSystem(this)">Оновити стан</button><button class="btn secondary" onclick="reloadModels()">Оновити моделі</button></div></header>
${s?`<section class="panel"><h2>Стан системи</h2><div class="metrics settings-metrics">${s.version?`<div><small>Версія</small><b>v${esc(s.version)}</b></div>`:''}<div><small>OpenAI API</small><b>${okBadge(s.openai_configured,'Налаштовано','Немає ключа')}</b></div><div><small>Gemini API</small><b>${s.gemini_configured?okBadge(true,'Налаштовано'):'<span class="muted-note">не підключено</span>'}</b></div><div><small>Черга (Redis)</small><b>${okBadge(s.redis_ok)}</b></div><div><small>Worker</small><b>${okBadge(s.worker_ok)}</b></div><div><small>Сторож зависань</small><b>${s.watchdog_minutes} хв</b></div><div><small>Бюджет сьогодні ${hint(state.me?.is_root?'Денна стеля витрат на AI (DAILY_BUDGET_USD у .env). Після вичерпання нові генерації зупиняються до наступної доби; запущені — завершуються.':'Денна стеля витрат на AI. Після вичерпання нові генерації зупиняються до наступної доби; запущені — завершуються.')}</small><b>${s.daily_budget_usd>0?`$${(s.today_spend_usd||0).toFixed(2)} із $${s.daily_budget_usd.toFixed(0)}`:'вимкнено'}</b></div><div><small>Сповіщення</small><b>${s.alerts_telegram||s.alerts_webhook?[s.alerts_telegram?'Telegram':'',s.alerts_webhook?'Webhook':''].filter(Boolean).join(' + '):'<span class="muted-note">вимкнено</span>'}</b></div></div>${!s.openai_configured?'<p class="critic-note">Без ключа OpenAI генерація працює в офлайн-режимі на вбудованому шаблоні.</p>':''}${!s.worker_ok?'<p class="critic-note">Worker не відповідає — нові проєкти застрягнуть у черзі. Перевірте <code>docker compose ps</code> на сервері.</p>':''}</section>
<section class="two"><div class="panel"><h2>Дані</h2><div class="metrics"><div><small>Проєкти</small><b>${s.projects}</b></div><div><small>Стилі</small><b>${s.styles}</b></div><div><small>Користувачі</small><b>${s.users}</b></div></div><div class="metrics"><div><small>Медіафайли</small><b>${s.media_files} · ${fmtBytes(s.media_bytes)}</b></div>${state.me?.is_root?`<div><small>Вільно на диску</small><b class="${s.disk_free_bytes&&s.disk_free_bytes<5*1024**3?'quality-bad':''}">${fmtBytes(s.disk_free_bytes)}</b></div>`:''}${state.me?.is_root?`<div><small>Схема БД</small><b>${esc(s.db_schema)}</b></div>`:''}</div></div><div class="panel"><h2>Моделі за замовчуванням</h2><div class="metrics"><div><small>Текст</small><b>${esc(s.default_text_model)}</b></div><div><small>Зображення</small><b>${esc(s.default_image_model)}</b></div><div><small>Reasoning effort</small><b>${esc(s.reasoning_effort||'—')}</b></div></div><p class="muted-note">Модель для конкретного проєкту можна змінити в діалозі створення.</p></div></section>`:'<section class="panel"><div class="empty">Завантаження стану системи…</div></section>'}
<section class="two"><div class="panel"><h2>Текстові моделі ${hint('Перелік задається у OPENAI_TEXT_MODELS в .env. Тут показані лише ті, що доступні на поточному ключі. Разову модель поза списком можна ввести в діалозі створення проєкту.')}</h2>${modelList(state.models.text_models,state.models.reasoning_models)}<h2>Моделі зображень ${hint('OPENAI_IMAGE_MODELS у .env плюс моделі Gemini, якщо збережено ключ Gemini.')}</h2>${modelList(state.models.image_models)}${modelNotes()}</div><div class="panel"><h2>Моделі міркування ${hint('Це не окремий список моделей, а ті з ваших текстових моделей, що витрачають частину бюджету відповіді на приховані міркування. Обсяг міркувань задається OPENAI_REASONING_EFFORT.')}</h2>${(state.models.reasoning_models||[]).length?modelList(state.models.reasoning_models):'<p class="muted-note">Жодна з обраних текстових моделей не витрачає токени на міркування.</p>'}<p class="muted-note">Джерело переліку: <b>${esc(state.models.source||'—')}</b>${state.models.source==='configuration+verified'?' — перевірено на живому ключі OpenAI':''}</p></div></section>
${secretsPanel()}
<section class="panel"><h2>Довідка</h2>${s?.code_graph_url?`<p class="muted-note"><a class="link" href="${s.code_graph_url}" target="_blank" rel="noopener">Мапа кодової бази (Graphify)</a> — інтерактивний граф модулів і зв'язків проєкту.</p>`:''}${state.me?.is_root?`<p class="muted-note">Посібник редактора — <code>docs/USER_GUIDE.md</code>, деплой і бекапи — <code>docs/DEPLOY.md</code> у репозиторії. Бекап БД створюється автоматично щодня контейнером <code>backup</code>.</p>`:'<p class="muted-note">З питань конфігурації та резервних копій зверніться до адміністратора.</p>'}</section>
${techStrip()}`)}
// Running strip of the technologies behind the studio (settings footer).
// Pure CSS marquee: two identical sequences, keyframes shift the track by -50%,
// so the full-page innerHTML re-render cannot desync it (no JS state to lose).
const TECH_STACK=[
 ['Python','#3776AB','https://www.python.org'],
 ['FastAPI','#009688','https://fastapi.tiangolo.com'],
 ['Celery','#37814A','https://docs.celeryq.dev'],
 ['PostgreSQL','#4169E1','https://www.postgresql.org'],
 ['Alembic','#6E7781','https://alembic.sqlalchemy.org'],
 ['Redis','#FF4438','https://redis.io'],
 ['Docker','#2496ED','https://www.docker.com'],
 ['Nginx','#009639','https://nginx.org'],
 ['Caddy','#6E7781','https://caddyserver.com'],
 ['OpenAI','#10A37F','https://platform.openai.com'],
 ['Gemini','#4E82EE','https://ai.google.dev'],
 ['OpenRouter','#6D64BB','https://openrouter.ai'],
 ['Vanilla JS','#D9B60A','https://developer.mozilla.org/docs/Web/JavaScript'],
];
function techStrip(){const seq=hidden=>`<div class="techloop-seq"${hidden?' aria-hidden="true"':''}>${TECH_STACK.map(([name,color,href])=>`<a class="techloop-item" style="--c:${color}" href="${href}" target="_blank" rel="noreferrer noopener">${name}</a>`).join('')}</div>`;
return `<section class="panel techloop-panel"><h2>Технології</h2><div class="techloop" role="region" aria-label="Використані технології"><div class="techloop-track">${seq(false)}${seq(true)}</div></div></section>`}

function balanceStrip(){const b=state.balances;if(!b)return '';const usd=v=>v==null?null:`$${Number(v).toFixed(2)}`;const row=(name,x)=>{if(!x.configured)return `<div><small>${name}</small><b class="muted-note">ключ не задано</b></div>`;const main=usd(x.balance)??usd(x.spend_30d)??'—';const capt=x.balance!=null?'на рахунку':'витрачено студією за 30 днів';return `<div><small>${name} · ${capt}${x.note?` ${hint(x.note)}`:''}</small><b>${main}</b></div>`};return `<div class="metrics">${row('OpenAI',b.openai)}${row('Gemini',b.gemini)}${row('OpenRouter',b.openrouter)}</div>`}
function secretsPanel(){if(!state.me?.is_root)return '';const k=state.secrets;if(!k)return `<section class="panel"><h2>Ключі та провайдер</h2><div class="empty">Завантаження…</div></section>`;const src=v=>v==='database'?'<span class="key-src db">збережено в БД</span>':v==='env'?'<span class="key-src env">з .env</span>':'<span class="key-src none">не задано</span>';const or=k.llm_provider==='openrouter';return `<section class="panel"><div class="panel-tools"><h2>Ключі та провайдер ${hint('Доступно лише головному адміністратору. Ключ зберігається в базі й перекриває значення з .env. API і worker підхоплюють новий ключ протягом ~15 секунд без перезапуску.')}</h2><div class="row"><button class="btn secondary" onclick="testSecrets(this)">Перевірити зв’язок</button></div></div>${balanceStrip()}<form class="secrets-form" onsubmit="saveSecrets(event)"><label>Провайдер тексту<select name="llm_provider" onchange="state.secrets.llm_provider=this.value;render()">${[['openai','OpenAI'],['openrouter','OpenRouter']].map(([v,l])=>`<option value="${v}" ${k.llm_provider===v?'selected':''}>${l}</option>`).join('')}</select></label><label>OpenAI API key ${src(k.openai_api_key_source)}<input name="openai_api_key" autocomplete="off" spellcheck="false" placeholder="${k.openai_api_key?esc(k.openai_api_key):'sk-…'}"></label><label>Gemini API key ${src(k.gemini_api_key_source)} ${hint('Додає моделі Nano Banana до списку моделей зображень у діалозі створення проєкту. Вони краще зберігають зовнішній вигляд товару і коштують у рази дешевше за gpt-image-1 high.')}<input name="gemini_api_key" autocomplete="off" spellcheck="false" placeholder="${k.gemini_api_key?esc(k.gemini_api_key):'AIza…'}"></label>${or?`<label>OpenRouter API key ${src(k.openrouter_api_key_source)}<input name="openrouter_api_key" autocomplete="off" spellcheck="false" placeholder="${k.openrouter_api_key?esc(k.openrouter_api_key):'sk-or-v1-…'}"></label><label>Модель OpenRouter<input name="openrouter_text_model" value="${esc(k.openrouter_text_model||'')}" spellcheck="false" placeholder="openai/gpt-4o-mini"></label>`:''}<p class="muted-note">Поле порожнє — ключ не змінюється. Щоб прибрати збережений ключ і повернутись до <code>.env</code>, введіть <code>-</code>.</p>${or?'<p class="critic-note">OpenRouter обслуговує лише текст: генерація зображень завжди йде через OpenAI, бо Images Edit з <code>input_fidelity</code> в OpenRouter немає. Ключ OpenAI має лишатись заповненим.</p>':''}<div class="row"><button class="btn primary">Зберегти ключі</button></div></form></section>`}
async function loadSecrets(){if(!state.me?.is_root)return;try{state.secrets=await api('/api/secrets')}catch{state.secrets=null}
try{state.balances=await api('/api/providers/balance')}catch{state.balances=null}}
async function saveSecrets(e){e.preventDefault();const f=new FormData(e.target),body={llm_provider:f.get('llm_provider')};for(const key of ['openai_api_key','gemini_api_key','openrouter_api_key','openrouter_text_model']){if(!f.has(key))continue;const v=(f.get(key)||'').trim();if(key==='openrouter_text_model'){body[key]=v;continue}if(!v)continue;body[key]=v==='-'?'':v}try{state.secrets=await api('/api/secrets',{method:'PUT',body:JSON.stringify(body)});e.target.reset();toast('Ключі збережено');await loadSystem();render()}catch(x){toast(x.message,true)}}
async function testSecrets(btn){btn.disabled=true;try{const r=await api('/api/secrets/test',{method:'POST'});toast(r.ok?`${r.provider}: зв’язок є, моделей ${r.models}`:`${r.provider}: ${r.detail}`,!r.ok)}catch(x){toast(x.message,true)}finally{btn.disabled=false}}
async function loadSystem(){try{state.system=await api('/api/system')}catch{state.system=null}}
async function reloadSystem(btn){if(btn){btn.disabled=true}try{await loadSystem();await loadSecrets();toast('Стан оновлено');render()}catch(x){toast(x.message,true)}finally{if(btn)btn.disabled=false}}
async function reloadModels(){try{state.models=await api('/api/models');toast('Список моделей оновлено');render()}catch(x){toast(x.message,true)}}
// render() writes the whole document in one go, so a throw halfway through leaves a
// half-built page and no error anywhere. Surface it, and tell the server once so the
// existing Telegram/webhook alerting sees frontend crashes too.
let crashReported=false;
function reportCrash(what,err){const text=`${what}: ${err&&(err.stack||err.message)||err}`.slice(0,600);console.error(what,err);try{toast('Помилка інтерфейсу — деталі в консолі',true)}catch{}if(crashReported||!state.token)return;crashReported=true;setTimeout(()=>{crashReported=false},60000);fetch('/api/client-error',{method:'POST',headers:{'Content-Type':'application/json',Authorization:`Bearer ${state.token}`},body:JSON.stringify({text,url:location.href,agent:navigator.userAgent})}).catch(()=>{})}
addEventListener('error',e=>reportCrash('Помилка скрипта',e.error||e.message));
addEventListener('unhandledrejection',e=>reportCrash('Необроблена помилка',e.reason));
function render(){if(!state.token)return loginView();if(state.selected){workspace();animateProgressBars();return}if(!allowedPages().includes(state.page))state.page=allowedPages()[0]||'projects';({projects:projectsPage,styles:stylesPage,media:mediaPage,usage:usagePage,users:usersPage,settings:settingsPage}[state.page]||projectsPage)();animateProgressBars()}
boot().catch(e=>{console.error(e);toast(e.message,true);render()});
